INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('16-patient-experience',2,16,'PATIENT EXPERIENCE','Trải nghiệm bệnh nhân',16,'draft','2026-06-20T14:46:10Z','2026-06-20T14:46:10Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('50d0b73f-8bcd-4b2c-915c-a3bb927f5125','16-patient-experience',NULL,2,'16.1 Patient Experience là gì?','161-patient-experience-la-gi',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0b5f3d6e-aec9-4430-aa9e-99281793ca95','50d0b73f-8bcd-4b2c-915c-a3bb927f5125',0,'image',NULL,'book/16-patient-experience/5b544e72-16cf-4cc3-9a39-74989be89cd0-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('98a6dbb8-522d-45ee-a7b8-d3fc4429bc1d','50d0b73f-8bcd-4b2c-915c-a3bb927f5125',1,'text','Trong kiến trúc vận hành của hệ điều hành Dental Empire OS, tôi luôn nhìn nhận phòng khám RHM không chỉ là một cơ sở y tế điều trị bệnh lý, mà là một **"nhà máy sản xuất trải nghiệm hạnh phúc"**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('779b656d-c9c2-44fd-bfb3-9f23efe7f0b5','50d0b73f-8bcd-4b2c-915c-a3bb927f5125',2,'text','Chúng ta đã nói rất nhiều về cách thu hút khách hàng ở các tầng Marketing, tối ưu tỷ lệ đặt lịch ở tầng Sales, hay chuẩn hóa chuyên môn ở tầng Clinic. Nhưng hãy thành thật với nhau một điều: Marketing chỉ tạo ra sự tò mò, Sales chỉ tạo ra cam kết đến khám, và Clinic tạo ra kết quả lâm sàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('269a4159-7a14-4c2a-839f-d6923158ceb5','50d0b73f-8bcd-4b2c-915c-a3bb927f5125',3,'text','Thứ duy nhất giữ bệnh nhân ở lại trọn đời, khiến họ gạt bỏ mọi định kiến sợ hãi để thực sự **thích làm răng** và tự nguyện trở thành một kênh truyền thông không công cho phòng khám - đó chính là **Patient Experience (Hệ thống trải nghiệm bệnh nhân)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cb9e77b2-f41f-4076-8a03-aa0cf4dccb20','50d0b73f-8bcd-4b2c-915c-a3bb927f5125',4,'text','Patient Experience không đơn thuần là câu chuyện "phục vụ tốt", lễ tân cười tươi hay trà nước chu đáo. Đó là một hệ thống được lập trình có chủ đích, can thiệp vào từng tầng cảm xúc của bệnh nhân từ giây phút đầu tiên họ bước chân qua cánh cửa, xuyên suốt quá trình điều trị tại ghế nha, cho đến nhiều năm sau đó khi họ quay lại tái khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13fb30b0-2e35-40df-8b14-8fccf850f2b0','50d0b73f-8bcd-4b2c-915c-a3bb927f5125',5,'text','Một hệ thống trải nghiệm bệnh nhân chuẩn mực sẽ giải quyết trọn vẹn 7 bài toán tâm lý:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f7119a9c-4f77-4dd5-a8c3-e2b814717da0','50d0b73f-8bcd-4b2c-915c-a3bb927f5125',6,'text','- Giúp bệnh nhân cảm thấy mình được quan tâm như một con người, chứ không phải một "ca bệnh" hay một "chỉ tiêu doanh thu".- Xây dựng lòng tin tuyệt đối vào năng lực của Bác sĩ và uy tín của phòng khám.- Giúp bệnh nhân thấu hiểu tường tận hành trình điều trị của mình để chủ động phối hợp.- Hóa giải và triệt tiêu mọi nỗi lo lắng, sợ đau, sợ biến chứng vốn có trong tiềm thức.- Đốc thúc bệnh nhân tuân thủ kỷ luật, quay lại tái khám đúng hẹn.- Kích hoạt mong muốn được để lại những đánh giá 5 sao (Review) xuất phát từ lòng biết ơn.- Biến bệnh nhân thành một đại sứ thương hiệu, sẵn sàng giới thiệu người thân, bạn bè đến điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('58f1fb68-f57a-466e-9c0d-b267d2053dab','50d0b73f-8bcd-4b2c-915c-a3bb927f5125',7,'image',NULL,'book/16-patient-experience/85ab636e-b546-47c8-ae21-366b5268f3c6-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('83082c93-5103-4fc2-8e79-d372f0fc0625','16-patient-experience',NULL,2,'16.2 Clinic System vs. Patient experience - Phân định giữa “phần cứng” lâm sàng và “phần mềm” cảm xúc','162-clinic-system-vs-patient-experience-phan-inh-giua-phan-cung-lam-sang-va-phan',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('96059949-f4b3-4bdc-b06b-b8c8f50a3f4e','83082c93-5103-4fc2-8e79-d372f0fc0625',8,'text','Trong quá trình tư vấn và chuẩn hóa vận hành cho các phòng khám RHM, tôi nhận ra một điểm gút mắt mà có đến 90% chủ nha khoa thường nhầm lẫn: **Đánh đồng chất lượng điều trị lâm sàng với trải nghiệm bệnh nhân.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8d729aa0-8eec-4bf7-92ed-1e579e4a4c16','83082c93-5103-4fc2-8e79-d372f0fc0625',9,'text','Nhiều người nói với tôi: *"Phòng khám của anh bác sĩ tay nghề rất cao, máy móc toàn hàng nhập khẩu, quy trình vô trùng đạt chuẩn bộ Y tế, nghĩa là trải nghiệm bệnh nhân tốt rồi đúng không?"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c2a4643d-0fa2-4028-a0de-53d4158d8636','83082c93-5103-4fc2-8e79-d372f0fc0625',10,'text','Câu trả lời của tôi luôn là: **Chưa đủ.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6af2a919-797a-4b47-8484-785e399716f8','83082c93-5103-4fc2-8e79-d372f0fc0625',11,'text','Trong hệ điều hành Dental Empire OS, chất lượng lâm sàng mới chỉ là điều kiện cần, còn trải nghiệm bệnh nhân mới là điều kiện đủ. Để đội ngũ của bạn không bị mơ hồ khi thực chiến, chúng ta bắt buộc phải phân rã và định vị rõ hai khái niệm này như hai mặt của một đồng xu: **Clinic System là "Phần cứng", còn Patient Experience là "Phần mềm" bao bọc xung quanh.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('629465f7-aad8-4886-8b61-4a175d4085f2','16-patient-experience','83082c93-5103-4fc2-8e79-d372f0fc0625',3,'Clinic System: Cái Gì &amp; Ai (Nền móng Chuyên môn)','clinic-system-cai-gi-amp-ai-nen-mong-chuyen-mon',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('57b1b5a7-1def-4c27-8c16-b0c8e27fba68','629465f7-aad8-4886-8b61-4a175d4085f2',12,'text','Clinic System tập trung hoàn toàn vào **Năng lực y khoa, Tiêu chuẩn kỹ thuật và Tính chính xác**. Hệ thống này sinh ra để trả lời cho một câu hỏi duy nhất của bệnh nhân: *"Phòng khám có làm đúng quy trình y tế, có an toàn và có chữa khỏi bệnh cho tôi không?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3998680-be86-4730-9494-e316f0636041','629465f7-aad8-4886-8b61-4a175d4085f2',13,'text','- **Yếu tố cốt lõi bao gồm:** Bằng cấp chuyên khoa của bác sĩ, hệ thống trang thiết bị hỗ trợ (máy CT Cone Beam, Piezotome, máy quét dấu hàm), quy trình kiểm soát vô khuẩn trung tâm, phác đồ điều trị tiêu chuẩn và chất lượng vật liệu nha khoa.- **Mục tiêu quản trị:** Triệt tiêu hoàn toàn các sai sót y khoa, tối ưu hóa công suất vận hành của ghế nha, chuẩn hóa năng lực điều trị đồng đều giữa các bác sĩ và trợ thủ.- **Nhân sự chịu trách nhiệm:** Bác sĩ trưởng ca, Bác sĩ điều trị và đội ngũ Trợ thủ lâm sàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bcd25ded-f76d-4d39-94a3-a715a31b94e2','16-patient-experience','83082c93-5103-4fc2-8e79-d372f0fc0625',3,'Patient Experience: Như Thế Nào &amp; Cảm Xúc (Đòn bẩy Tâm lý)','patient-experience-nhu-the-nao-amp-cam-xuc-on-bay-tam-ly',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('323dd6f2-3388-4c54-92d2-86479eb74f49','bcd25ded-f76d-4d39-94a3-a715a31b94e2',14,'text','Patient Experience tập trung vào **Hành trình cảm xúc và Điểm chạm tâm lý** của bệnh nhân. Hệ thống này không hỏi về kết quả y khoa, mà hỏi về cảm giác: *"Bệnh nhân cảm thấy thế nào trong suốt quá trình tiếp xúc với phòng khám — từ trước, trong, cho đến sau khi điều trị?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('45b38776-fee7-4b0b-bd32-1b8751e144e5','bcd25ded-f76d-4d39-94a3-a715a31b94e2',15,'text','- **Yếu tố cốt lõi bao gồm:** Mùi hương tinh dầu dễ chịu tại sảnh đón tiếp thay cho mùi cồn y tế; âm nhạc thư giãn; kịch bản giao tiếp giải tỏa nỗi sợ của bác sĩ trên ghế nha; tốc độ phản hồi tin nhắn của lễ tân; những dòng tin nhắn dặn dò hậu phẫu tự động và cách xin review tinh tế từ bộ phận chăm sóc.- **Mục tiêu quản trị:** Xóa bỏ rào cản e ngại, biến một thủ tục y khoa vốn mang đầy lo âu thành một trải nghiệm nhẹ nhàng, giúp bệnh nhân thực sự **thích làm răng**. Từ đó kích hoạt lòng trung thành, đẩy cao tỷ lệ tái khám và thúc đẩy sự giới thiệu tự nhiên (Referral).- **Nhân sự chịu trách nhiệm:** Bộ phận Chăm sóc bệnh nhân (Patient Care), Lễ tân, kết hợp chặt chẽ với thái độ giao tiếp của đội ngũ Bác sĩ lâm sàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ee93df83-5845-4265-ab3f-ce302bfc79be','16-patient-experience','83082c93-5103-4fc2-8e79-d372f0fc0625',3,'Bài Học Xương Máu Từ Ghế Nha: Khi Hai Hệ Thống Lệch Pha','bai-hoc-xuong-mau-tu-ghe-nha-khi-hai-he-thong-lech-pha',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4d63255a-4356-4b88-ae6e-92947181fab2','ee93df83-5845-4265-ab3f-ce302bfc79be',16,'text','Để hiểu vì sao hai phần này không thể tách rời nhưng phải phân định rõ, hãy nhìn vào hai kịch bản kinh điển dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4c29c3ca-fa15-4c83-b085-ebc78c5bc94c','ee93df83-5845-4265-ab3f-ce302bfc79be',17,'text','**Kịch bản 1: Clinic System TỐT nhưng Patient Experience TỆ** Bác sĩ cấy ghép một trụ Implant chuẩn xác 100% đến từng milimet, phòng phẫu thuật vô trùng tuyệt đối. Nhưng suốt ca làm, bác sĩ lạnh lùng không nói một lời, trợ thủ thao tác thô bạo khiến nước bọt tràn ra, phòng khám nồng nặc mùi hôi khiến bệnh nhân hoảng sợ. Khi họ về nhà, không một ai nhắn tin hỏi thăm xem họ có đau hay sốt không. *Hậu quả:* Ca điều trị thành công rực rỡ về mặt y khoa, nhưng **thất bại hoàn toàn về mặt kinh doanh**. Bệnh nhân sẽ mang một tâm lý sang chấn, một đi không trở lại và tuyệt đối không bao giờ giới thiệu người thân đến phòng khám của bạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('db8d84d2-42a3-4621-b44e-fcc0f7df7a0d','ee93df83-5845-4265-ab3f-ce302bfc79be',18,'text','**Kịch bản 2: Clinic System TỆ nhưng Patient Experience TỐT** Nhân viên tiếp đón vồ vập, nước trà thơm phức, không gian sang trọng như khách sạn, bác sĩ nói chuyện cực kỳ ngọt ngào và tâm lý... nhưng năng lực yếu kém, cắm Implant sai hướng gây tiêu xương và biến chứng cho bệnh nhân. *Hậu quả:* Phòng khám sụp đổ ngay lập tức vì vi phạm lằn ranh sinh tử của đạo đức ngành y và pháp luật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0219cb51-43fc-44c8-b1e2-08f7b262ad22','16-patient-experience',NULL,2,'16.3 Bóc tách 5 giai đoạn kim cương của trải nghiệm bệnh nhân','163-boc-tach-5-giai-oan-kim-cuong-cua-trai-nghiem-benh-nhan',5,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ffeb07bb-3fe6-48a0-a2e8-263178bc5249','16-patient-experience','0219cb51-43fc-44c8-b1e2-08f7b262ad22',3,'Giai Đoạn Khám: Điểm Chạm Đầu Tiên Và Nghệ Thuật Đồng Cảm','giai-oan-kham-iem-cham-au-tien-va-nghe-thuat-ong-cam',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4e030b27-6671-4fbd-9866-51c9ac7f0cce','ffeb07bb-3fe6-48a0-a2e8-263178bc5249',19,'text','Trải nghiệm bắt đầu trước khi bệnh nhân nhìn thấy Bác sĩ. Ngay tại sảnh đón tiếp, từ cách lễ tân chào bằng tên riêng, sự ngăn nắp của quầy đón tiếp cho đến mùi hương tinh dầu nhẹ nhàng thay cho mùi cồn y tế đặc trưng - tất cả đều nhằm mục đích hạ mức lo âu của bệnh nhân xuống mức thấp nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9f49cac6-1f84-4430-8c46-e3e8c9c40454','ffeb07bb-3fe6-48a0-a2e8-263178bc5249',20,'text','Khi bước vào phòng khám lâm sàng để chụp phim, trải nghiệm được dẫn dắt bởi sự minh bạch. Bác sĩ không phán bệnh một cách áp đặt. Bác sĩ dùng hình ảnh trực quan trên màn hình, giải thích cặn kẽ: *"Tình trạng hiện tại của anh/chị là gì? Vì sao nó lại bị như vậy?"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('057da534-1ee8-446a-ac44-7eeb2bd928a5','ffeb07bb-3fe6-48a0-a2e8-263178bc5249',21,'text','**Mantra giai đoạn khám:** Một buổi thăm khám xuất sắc là khi bệnh nhân hiểu rõ răng miệng của mình như một người trong ngành, từ đó mọi rào cản về chi phí hay nỗi sợ đều bị xóa bỏ, nhường chỗ cho sự đồng ý điều trị tự nguyện.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9a00bc67-82be-4827-9e45-0cdfddb7e380','16-patient-experience','0219cb51-43fc-44c8-b1e2-08f7b262ad22',3,'Giai Đoạn Điều Trị: Sự Thật Trên Ghế Nha và Năng Lực Cốt Lõi','giai-oan-ieu-tri-su-that-tren-ghe-nha-va-nang-luc-cot-loi',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8e4a29cc-bcef-4edd-bebe-f380a1ad7244','9a00bc67-82be-4827-9e45-0cdfddb7e380',22,'text','Đây là vùng lõi của chuyên môn lâm sàng. Năng lực của Bác sĩ không chỉ thể hiện ở việc đi mũi kim chính xác hay mài răng đúng tỷ lệ, mà nằm ở kỹ năng giao tiếp trong lúc điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3b0b13e7-911e-4740-a24b-9a552c3be96e','9a00bc67-82be-4827-9e45-0cdfddb7e380',23,'text','Bệnh nhân nằm trên ghế nha, bị nhắm mắt và nghe tiếng máy khoan sẽ vô cùng hoảng sợ. Hệ thống trải nghiệm đòi hỏi Bác sĩ và trợ thủ phải liên tục tương tác nhẹ nhàng: *"Bước này hơi ê một chút trong 3 giây nhé ạ", "Anh/chị làm tốt lắm, chúng ta đi được nửa chặng đường rồi"*. Sự dặn dò, quan tâm từng nhịp thở của khách hàng chính là lằn ranh phân biệt giữa một thợ làm răng thuần túy và một chuyên gia trải nghiệm đẳng cấp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e7b3b768-f68b-46ff-a041-80c1f411108c','16-patient-experience','0219cb51-43fc-44c8-b1e2-08f7b262ad22',3,'Giai Đoạn Chăm Sóc: Chốt Chặn Sau Cửa Phòng Khám','giai-oan-cham-soc-chot-chan-sau-cua-phong-kham',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5dafdd62-fb6c-472a-9bdf-12a9e3e250f8','e7b3b768-f68b-46ff-a041-80c1f411108c',24,'text','Trải nghiệm không kết thúc khi bệnh nhân đứng dậy thanh toán và ra về. Ngược lại, giai đoạn hậu phẫu mới là lúc họ cần phòng khám nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fdb593e8-67db-4d69-9fb6-fac669f63825','e7b3b768-f68b-46ff-a041-80c1f411108c',25,'text','Hệ thống Automation và đội ngũ Patient Care phải phối hợp nhịp nhàng: Gửi ngay tin nhắn dặn dò y khoa qua Zalo (cách uống thuốc, chế độ ăn uống, cách chườm đá). Đúng 8h tối ngày hôm đó, một cuộc gọi hoặc tin nhắn hỏi thăm cá nhân hóa: *"Hôm nay răng anh/chị đã bớt ê chưa?"* sẽ tạo ra một cú chạm cảm xúc cực mạnh. Họ nhận ra mình không bị bỏ rơi sau khi đã xuống tiền.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2af20440-a2e2-4b69-b22f-6b8e0db52c51','16-patient-experience','0219cb51-43fc-44c8-b1e2-08f7b262ad22',3,'Giai Đoạn Tái Khám: Nuôi Dưỡng Vòng Đời Bền Vững (LTV)','giai-oan-tai-kham-nuoi-duong-vong-oi-ben-vung-ltv',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d79dd40-9b84-4213-807d-4e23ab98ad2e','2af20440-a2e2-4b69-b22f-6b8e0db52c51',26,'text','Như đã chuẩn hóa ở chương trước, tái khám là trục xương sống của tài chính. Hệ thống trải nghiệm biến các lịch hẹn recall (nhắc khám định kỳ 6 tháng) trở thành một đặc quyền chăm sóc sức khỏe chủ động. Khách hàng quay lại không phải vì bị chèo kéo, mà vì họ muốn bảo vệ khối tài sản nụ cười đã được phòng khám kiến tạo. Mỗi lần tái khám là một lần củng cố thêm sợi dây gắn kết giữa khách hàng và thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('765bf135-30ad-4d4a-9376-81bc46334324','16-patient-experience','0219cb51-43fc-44c8-b1e2-08f7b262ad22',3,'Giai Đoạn Review &amp; Kích Hoạt Hệ Thống Lan Tỏa (Referral)','giai-oan-review-amp-kich-hoat-he-thong-lan-toa-referral',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('82fc43f0-52b5-4f21-a329-d7860b9fc7f8','765bf135-30ad-4d4a-9376-81bc46334324',27,'text','Khi tất cả 4 giai đoạn trên được vận hành không một tì vết, sự hài lòng của bệnh nhân sẽ đạt đỉnh (Wow Peak). Đây là thời điểm vàng để thu hoạch **Trust Assets**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6878c49c-81ae-45e0-9e9b-992b90e23a6b','765bf135-30ad-4d4a-9376-81bc46334324',28,'text','Khi bộ phận CSKH mở lời xin Review hoặc quay một đoạn video Testimonial ngắn, bệnh nhân sẽ không ngần ngại chia sẻ bằng tất cả sự hào hứng. Và từ những lời khen thật đó, một chương trình Referral tinh tế được kích hoạt: *"Phòng khám gửi tặng 3 suất tầm soát răng miệng miễn phí để anh/chị dành tặng cho những người thân yêu nhất của mình..."*. Vòng lặp tăng trưởng chính thức khép kín, tự động sinh ra một dòng chảy bệnh nhân mới chất lượng cao mà không tốn thêm một đồng chi phí quảng cáo nào.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1033f185-dd8c-4f22-8794-68b60114187e','16-patient-experience','0219cb51-43fc-44c8-b1e2-08f7b262ad22',3,'Tóm lại','tom-lai',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('278f6c4a-e89c-4def-94fb-6f8d72e3ef7c','1033f185-dd8c-4f22-8794-68b60114187e',29,'text','Xây dựng Patient Experience là việc bạn chuyển dịch tư duy từ **"chữa một chiếc răng"** sang **"chăm sóc một con người"**. Khi toàn bộ đội ngũ từ Lễ tân, Trợ thủ, Bác sĩ cho đến nhân viên CSKH - thấm nhuần kỷ luật trải nghiệm này, phòng khám của bạn sẽ sở hữu một thứ tài sản vô hình nhưng có sức mạnh hủy diệt mọi đối thủ cạnh tranh. Đó chính là tình yêu và lòng trung thành tuyệt đối của bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5b0fe315-f831-413f-8d15-be8349add101','16-patient-experience',NULL,2,'16.4 Bản đồ trải nghiệm tổng thể:','164-ban-o-trai-nghiem-tong-the',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('86a71849-2d62-457f-bb40-3d4ad2a8867c','5b0fe315-f831-413f-8d15-be8349add101',30,'image',NULL,'book/16-patient-experience/c2b7bba5-2b80-4d16-9bc5-16d1a0d0c8d4-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7f9407b4-8bec-47f2-8767-147bb88a6bfc','16-patient-experience',NULL,2,'16.5 Chi tiết triển khai cho 5 giai đoạn','165-chi-tiet-trien-khai-cho-5-giai-oan',13,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('33e8c675-8bc0-4ead-b0a9-c60fdfda6469','16-patient-experience','7f9407b4-8bec-47f2-8767-147bb88a6bfc',3,'Giai đoạn 1 - KHÁM: nghệ thuật chinh phục niềm tin từ điểm chạm đầu tiên','giai-oan-1-kham-nghe-thuat-chinh-phuc-niem-tin-tu-iem-cham-au-tien',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d2cefb3-2e97-44ea-9b15-e234d28d604c','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',31,'text','Trong hành trình trải nghiệm của bệnh nhân, giai đoạn Khám chính là **"khoảnh khắc của sự thật" (Moment of Truth)** đầu tiên tại thế giới vật lý. Tất cả những gì chúng ta hứa hẹn trên TikTok, Facebook hay Website sẽ được bệnh nhân mang ra đối chiếu và kiểm chứng ngay trong những phút đầu tiên này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f033106b-a1ad-4456-8dfd-04fc83d42724','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',32,'text','Ở giai đoạn này, bệnh nhân sẽ âm thầm đóng vai một vị giám khảo khắt khe để đánh giá toàn diện phòng khám thông qua các câu hỏi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f6ab7555-92ce-42ec-9992-1b2130c87894','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',33,'text','- Không gian và quy trình ở đây có thực sự chuyên nghiệp như trên mạng?- Nhân sự từ lễ tân đến phụ tá có thân thiện, chu đáo không?- Vị bác sĩ đang ngồi đối diện mình có thực sự đủ tầm và đáng tin?- Mọi giải thích về bệnh lý và chi phí có minh bạch, rõ ràng?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3c9cde4c-0fbc-42a0-b171-b27d4468e98c','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',34,'text','Mục tiêu cốt lõi của giai đoạn Khám không phải là tìm mọi cách để "chốt sale", mà là thiết lập một phương trình trải nghiệm chuẩn mực:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5715a0b1-7360-4261-b6e2-bf3cbc814568','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',35,'text','**[Cảm giác an tâm ban đầu] + [Dữ liệu lâm sàng chuẩn xác] + [Giải thích thấu đáo vấn đề] = Quyết định điều trị tự nguyện (Conversion)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3097ff81-0f01-48b9-800e-efe5c5e4241f','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',36,'image',NULL,'book/16-patient-experience/e1fc1664-adec-4cbb-8f23-ff70d915d2e9-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('750cf389-807b-4867-ad64-e5b96bdf4740','16-patient-experience','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',4,'Bảy điểm chạm chiến lược trong giai đoạn KHÁM','bay-iem-cham-chien-luoc-trong-giai-oan-kham',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('031d4d33-57df-4700-945d-de70e46d52c3','750cf389-807b-4867-ad64-e5b96bdf4740',37,'text','Để dòng chảy trải nghiệm không xuất hiện bất kỳ một vết gợn nào, hành trình khám tại phòng khám cần được chia nhỏ thành 7 điểm chạm vật lý kết nối chặt chẽ với nhau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd674e36-fb26-425d-80ed-50ce1b80e1ff','750cf389-807b-4867-ad64-e5b96bdf4740',38,'text','- **Điểm chạm 1: Bảo vệ & Khu vực giữ xe (Ấn tượng vật lý đầu tiên):** Nơi quyết định tâm trạng vui vẻ hay bực bội của bệnh nhân trước khi bước vào cửa.- **Điểm chạm 2: Quầy lễ tân & Sảnh chờ (Sự đón tiếp và xoa dịu):** Nơi xúc giác, thính giác và thị giác của khách hàng được giải tỏa nỗi sợ hãi.- **Điểm chạm 3: Phòng chụp phim / X-quang (Sự hiện đại của công nghệ):** Điểm chứng minh quy mô và tính chính xác của Clinic System.- **Điểm chạm 4: Ghế nha tư vấn (Nơi đối thoại Chuyên môn & Thấu cảm):** Không gian cốt lõi giữa Bác sĩ và bệnh nhân.- **Điểm chạm 5: Quầy tư vấn / Thanh toán (Minh bạch thông tin & Tài chính):** Nơi đóng gói kế hoạch điều trị và làm rõ chi phí.- **Điểm chạm 6: Hệ thống CRM & Hậu trường dữ liệu (Số hóa hành trình):** Điểm chạm số giúp lưu trữ, phân loại và kích hoạt các kịch bản chăm sóc tiếp theo.- **Điểm chạm 7: Khu vực Toilet / Nhà vệ sinh (Điểm chạm ẩn về sự tinh tế):** "Căn phòng tâm lý" nơi bệnh nhân ẩn nấp để tự kiểm tra nụ cười, giải tỏa căng thẳng hoặc soi gương sau khi thăm khám. Khách hàng sẽ cực kỳ hài lòng và tăng sự tin tưởng về vệ sinh của phòng khám thông qua sự sạch sẽ thơm tho của nhà vệ sinh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8ddb09e5-2214-4334-ac79-5a31f45ceb65','750cf389-807b-4867-ad64-e5b96bdf4740',39,'image',NULL,'book/16-patient-experience/092b8311-a662-4aba-94b5-2e275c8a7501-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9f1f6028-e21c-4a07-abd3-4d037f77a0b1','16-patient-experience','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',4,'Lớp đệm: Trước khi bệnh nhân đến (Hậu trường chuẩn bị)','lop-em-truoc-khi-benh-nhan-en-hau-truong-chuan-bi',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('07666ff9-d102-4ef7-9cd2-6e47f31f9835','9f1f6028-e21c-4a07-abd3-4d037f77a0b1',40,'text','- **Xác nhận lịch hẹn:** Đã gọi điện hoặc nhắn tin xác nhận lại thời gian cụ thể với bệnh nhân.- **Gửi chỉ đường chủ động:** Đã gửi link Google Maps kèm hướng dẫn vị trí đỗ xe trực quan cho cả xe máy và ô tô.- **Dặn dò y khoa:** Gửi trước các lưu ý cần thiết (ví dụ: ăn nhẹ trước khi nhổ răng khôn, mang theo hồ sơ cũ).- **Thấu hiểu nhu cầu:** Ghi chú rõ lý do đến khám chính của bệnh nhân vào hồ sơ điện tử.- **Phân loại tệp khách hàng:** Định danh rõ nguồn khách trên CRM (Khách từ Ads, Google, TikTok, hay được người quen giới thiệu) để nhân sự tiếp đón có tâm thế phù hợp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5a919fdd-a1d0-4f7e-bb3b-b3ba86cc5bd4','16-patient-experience','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',4,'Điểm chạm 1: Bảo vệ &amp; Khu vực giữ xe (Cánh cổng đầu tiên)','iem-cham-1-bao-ve-amp-khu-vuc-giu-xe-canh-cong-au-tien',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f720aa41-2607-47d8-a9e2-6e54a542a40d','5a919fdd-a1d0-4f7e-bb3b-b3ba86cc5bd4',41,'text','- **Chủ động đón tiếp:** Bảo vệ tươi cười, chủ động dắt xe, che yên nắng/mưa cho bệnh nhân ngay khi họ vừa tấp xe vào vỉa hè.- **Hỗ trợ thời tiết:** Chủ động che ô (dù) đón khách từ cửa xe ô tô hoặc từ bãi xe vào đến cửa phòng khám nếu trời mưa hoặc nắng gắt.- **Kết nối nội bộ:** Sử dụng bộ đàm hoặc tín hiệu thông báo trước cho lễ tân bên trong khi thấy khách hàng có lịch hẹn chuẩn bị bước vào.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a6e87a1c-eced-4dc0-b477-feede0797b60','16-patient-experience','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',4,'Điểm chạm 2: Quầy lễ tân &amp; Sảnh chờ (Xoa dịu năm giác quan)','iem-cham-2-quay-le-tan-amp-sanh-cho-xoa-diu-nam-giac-quan',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e304f7a5-2dfe-48ef-a9cd-4e0cf325ed59','a6e87a1c-eced-4dc0-b477-feede0797b60',42,'text','- **Chào hỏi cá nhân hóa:** Lễ tân đứng dậy chào bệnh nhân bằng tên riêng ngay khi họ bước qua cửa (Ví dụ: *"Dạ, em chào anh Vinh, anh có lịch hẹn khám lúc 9h đúng không ạ?"*).- **Tiếp đón tinh tế:** Mời nước uống (trà thảo mộc hoặc nước ấm tùy mùa) và hướng dẫn khách cất đồ cá nhân, thay dép mượt mà.- **Giải thích quy trình:** Nói rõ cho bệnh nhân biết họ sẽ trải qua những bước nào để họ chủ động tâm lý, không bị bỡ ngỡ.- **Kiểm soát thời gian chờ:** Tuyệt đối không để bệnh nhân đợi quá lâu mà không được cập nhật lý do. Nếu bác sĩ đang bận ca trước, lễ tân phải chủ động đến xin lỗi và thông báo chính xác thời gian chờ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e11bb001-50df-40e6-acd7-76089f30f710','16-patient-experience','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',4,'Điểm chạm 3: Phòng chụp phim / X-quang (Bảo chứng công nghệ)','iem-cham-3-phong-chup-phim-x-quang-bao-chung-cong-nghe',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('66a24559-e134-4c01-8d38-500595d7fa12','e11bb001-50df-40e6-acd7-76089f30f710',43,'text','- **Trấn an tâm lý:** Kỹ thuật viên hoặc trợ thủ giải thích ngắn gọn lý do cần chụp phim và độ an toàn của máy để giảm sợ hãi cho khách.- **Bảo vệ sức khỏe:** Hướng dẫn khách đeo tạp dề chì đúng quy chuẩn để chắn tia X, thể hiện sự kỹ lưỡng của một cơ sở y tế cao cấp.- **Thao tác êm ái:** Hướng dẫn khách vị trí cắn răng, giữ đầu nhẹ nhàng, tránh làm đau hoặc khiến khách khó chịu khi đặt máng chụp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a9a07639-b605-4872-9228-0c11a1dd7e7e','16-patient-experience','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',4,'Điểm chạm 4: Ghế nha tư vấn (Chữ "Tâm" trên ghế lâm sàng)','iem-cham-4-ghe-nha-tu-van-chu-tam-tren-ghe-lam-sang',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d55b75de-d596-42c5-9ca7-5501bdb4494e','a9a07639-b605-4872-9228-0c11a1dd7e7e',44,'text','- **Lắng nghe chủ động:** Bác sĩ bắt đầu bằng việc lắng nghe bệnh nhân chia sẻ về nỗi đau, sự khó chịu hoặc mong muốn cải thiện nụ cười.- **Khai thác kỳ vọng sâu:** Hỏi kỹ về những nỗi sợ thầm kín (sợ đau, sợ tiếng máy kêu) để có phương án xoa dịu trong lúc điều trị.- **Trực quan hóa bệnh lý:** Sử dụng phim chụp X-quang hoặc hình ảnh scan 3D hiển thị trên màn hình lớn trước mặt để giải thích. Tuyệt đối không nói suông.- **Bình dân hóa ngôn từ:** Tránh lạm dụng các thuật ngữ y khoa quá hàn lâm. Hãy dùng những hình ảnh ẩn dụ dễ hiểu để giải thích nguyên nhân và nguy cơ nếu không xử lý.- **Tư vấn trung thực:** Tuyệt đối không chèo kéo, dồn ép khách làm dịch vụ giá cao nếu không thực sự cần thiết về mặt y khoa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5a85f1a4-41a2-4495-bcd0-c7e9566e2427','16-patient-experience','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',4,'Điểm chạm 5: Quầy tư vấn &amp; Thanh toán (Minh bạch tài chính)','iem-cham-5-quay-tu-van-amp-thanh-toan-minh-bach-tai-chinh',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1852e686-bed2-4247-9239-dfcadee5f352','5a85f1a4-41a2-4495-bcd0-c7e9566e2427',45,'text','- **Tóm tắt kế hoạch:** Chuyên viên tư vấn tóm tắt lại một lần nữa phác đồ điều trị, các giai đoạn và thời gian hoàn thành bằng văn bản rõ ràng.- **Minh bạch tài chính:** Cung cấp bảng chi phí chi tiết từng hạng mục, chính sách trả góp, cam kết bảo hành và khẳng định không phát sinh chi phí ẩn.- **Ghi nhận băn khoăn:** Lắng nghe và ghi chú lại các do dự cuối cùng của bệnh nhân (về tài chính, thời gian sắp xếp công việc) để hỗ trợ giải quyết thay vì ép chốt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9e708378-6701-4481-ac61-7a4a2c0ae8ff','16-patient-experience','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',4,'Điểm chạm 6: Hệ thống CRM &amp; Hậu trường dữ liệu (Số hóa thông tin)','iem-cham-6-he-thong-crm-amp-hau-truong-du-lieu-so-hoa-thong-tin',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('88c6ccef-8f9f-402c-90ab-772d067ae41e','9e708378-6701-4481-ac61-7a4a2c0ae8ff',46,'text','- **Cập nhật trạng thái:** Ngay khi khách hoàn thành ca khám, toàn bộ dữ liệu phim chụp, phác đồ và ghi chú tâm lý phải được đẩy lên hệ thống CRM.- **Gắn Tag phân loại:** Gắn tag chính xác tình trạng (Ví dụ: *Khách mới - Đang cân nhắc Implant - Sợ đau*) để kích hoạt chuỗi tin nhắn hoặc cuộc gọi follow-up tự động phù hợp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9c728a06-c0b1-4b2b-9b47-c0b3250aed35','16-patient-experience','33e8c675-8bc0-4ead-b0a9-c60fdfda6469',4,'Điểm chạm 7: Khu vực Toilet / Nhà vệ sinh (Sự tinh tế tuyệt đối)','iem-cham-7-khu-vuc-toilet-nha-ve-sinh-su-tinh-te-tuyet-oi',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b686e396-932e-4801-82a4-6caeb1e3cb3f','9c728a06-c0b1-4b2b-9b47-c0b3250aed35',47,'text','**Ghi chú vận hành:** Nhà vệ sinh là nơi bệnh nhân thường "trốn" vào để soi gương tự kiểm tra răng miệng trước khi khám, hoặc đứng chỉnh đốn lại diện mạo, lau vết son/vết máu sau khi bước xuống khỏi ghế nha. Sự sạch sẽ và chu đáo ở đây có sức nặng củng cố niềm tin cực lớn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('19e32018-0d91-4e3f-84e5-5aa1cfc7b8c0','9c728a06-c0b1-4b2b-9b47-c0b3250aed35',48,'text','- **Vệ sinh tuyệt đối:** Sàn nhà luôn khô ráo, gương lớn luôn được lau sạch không một vết mờ hay giọt nước bắn, thùng rác không bị đầy.- **Mùi hương tinh tế:** Tuyệt đối không có mùi hôi hoặc mùi nước tẩy rửa nồng nặc. Sử dụng tinh dầu sả chanh hoặc quế nhẹ nhàng để tạo cảm giác thư giãn như spa.- **Tiện ích đầy đủ cho răng miệng: c**huẩn bị sẵn bàn chải đánh răng dùng một lần (đã có sẵn kem), nước súc miệng kháng khuẩn, chỉ nha khoa và khăn giấy lau tay cao cấp để bệnh nhân thoải mái sử dụng trước và sau khi khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1112334e-95b7-4eb8-a2f9-6184d6ddc567','16-patient-experience','7f9407b4-8bec-47f2-8767-147bb88a6bfc',3,'Giai đoạn 2 - ĐIỀU TRỊ: bài kiểm tra bản lĩnh lâm sàng và nghệ thuật thao tác cảm xúc trên ghế nha','giai-oan-2-ieu-tri-bai-kiem-tra-ban-linh-lam-sang-va-nghe-thuat-thao-tac-cam-xuc',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ada9379d-ca1d-4bad-a665-3771d5a5562f','1112334e-95b7-4eb8-a2f9-6184d6ddc567',49,'text','Nếu giai đoạn Khám là bước xây dựng niềm tin trên giấy tờ và phim chụp, thì **Giai đoạn 2 - Điều trị** chính là lúc bệnh nhân dùng toàn bộ các giác quan của mình để kiểm chứng năng lực thực tế của phòng khám RHM. Đây là khúc cua nhạy cảm nhất trong chuỗi trải nghiệm bệnh nhân của hệ điều hành **Dental Empire OS**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0501bd15-b393-4562-a9b1-5e8895375e7c','1112334e-95b7-4eb8-a2f9-6184d6ddc567',50,'text','Trong tâm thức của đại đa số người dân, bước vào phòng điều trị nha khoa đồng nghĩa với việc đối mặt với nỗi sợ: sợ tiếng máy khoan, sợ kim tiêm, sợ mùi thuốc và sợ cảm giác đau đớn. Vì vậy, một ca điều trị thành công xuất sắc không bao giờ chỉ dừng lại ở kết quả kỹ thuật lâm sàng của **Clinic System**. Nó bắt buộc phải là sự dung hợp hoàn hảo giữa kỹ trị chuyên môn và nghệ thuật xoa dịu tâm lý, giúp bệnh nhân vượt qua nỗi sợ để thực sự cảm thấy an tâm, an toàn và tiến gần hơn đến tinh thần **thích làm răng**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('56350f9a-0eb2-494b-ba62-4e17252509dd','1112334e-95b7-4eb8-a2f9-6184d6ddc567',51,'text','Mục tiêu tối thượng của giai đoạn này được định hình bằng một công thức vận hành nghiêm ngặt:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fe0571ce-6ac9-4905-a86a-209d0867da73','1112334e-95b7-4eb8-a2f9-6184d6ddc567',52,'text','**[Điều trị đúng chuyên môn chuẩn y khoa] + [Kiểm soát và triệt tiêu nỗi lo âu] + [Thiết lập không gian an toàn tuyệt đối] = Lòng tin bất di bất dịch vào Bác sĩ & Hệ thống**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8af2f5b7-cd49-444e-8f0c-04dcd365c36f','1112334e-95b7-4eb8-a2f9-6184d6ddc567',53,'image',NULL,'book/16-patient-experience/50a7d977-d2f1-475d-b27e-56fad5a241d4-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8304d4ad-d029-4ac3-90d0-5f054189540b','16-patient-experience','1112334e-95b7-4eb8-a2f9-6184d6ddc567',4,'Các điểm chạm chiến lược trong giai đoạn điều trị','cac-iem-cham-chien-luoc-trong-giai-oan-ieu-tri',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('86642772-73c6-4bcf-80a9-622b5f1275c5','8304d4ad-d029-4ac3-90d0-5f054189540b',54,'text','Để biến một quy trình can thiệp y khoa thô cứng thành một hành trình trải nghiệm êm ái, phòng khám cần quản trị nghiêm ngặt 5 điểm chạm vật lý và cảm xúc dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c57e6b95-42f9-4012-88c9-f698da6fc542','8304d4ad-d029-4ac3-90d0-5f054189540b',55,'text','- **Điểm chạm 1: Sảnh chờ chuẩn bị tâm lý (Pre-treatment Lounge):** Không gian đệm nơi bệnh nhân được nghỉ ngơi, uống nước và ổn định nhịp tim trước khi bước vào vùng điều trị.- **Điểm chạm 2: Hành lang chuyển tiếp (The Transitional Corridor):** Khoảng không gian di chuyển từ sảnh chờ vào phòng máy. Sự yên tĩnh và sạch sẽ ở đây đóng vai trò như một bộ lọc ngăn cách tiếng ồn, giảm căng thẳng từ xa.- **Điểm chạm 3: Ghế nha điều trị & Hệ sinh thái thiết bị (The Treatment Hub):** Điểm chạm cốt lõi nơi cơ thể bệnh nhân tiếp xúc trực tiếp với máy móc, ánh sáng đèn halogen và tay khoan kỹ thuật.- **Điểm chạm 4: Hệ thống tương tác giác quan (Sensory Touchpoint):** Sự kết hợp giữa kính bảo hộ che mắt, âm nhạc trị liệu qua loa/tai nghe và kỹ thuật bôi/tê không đau của bác sĩ.- **Điểm chạm 5: Quầy hậu phẫu / Bàn giao dặn dò (Post-op Desk):** Nơi khách hàng bước xuống khỏi ghế nha, được xoa dịu, nhìn ngắm kết quả ban đầu và nhận cẩm nang chăm sóc tại nhà.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0b36b210-b0f4-4abf-8fc5-66fda8537e06','16-patient-experience','1112334e-95b7-4eb8-a2f9-6184d6ddc567',4,'Checklist vận hành trải nghiệm trong điều trị chi tiết','checklist-van-hanh-trai-nghiem-trong-ieu-tri-chi-tiet',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fae5eb42-efd0-496f-a1b8-43c639d870fe','0b36b210-b0f4-4abf-8fc5-66fda8537e06',56,'text','Dưới đây là bộ checklist hành động thực chiến dành cho ba phân khúc thời gian: Trước, Trong và Sau khi điều trị trên ghế răng, áp dụng đồng bộ cho cả Bác sĩ và đội ngũ Trợ thủ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7a2e118b-57be-4763-8ce5-e797fbc7aca6','0b36b210-b0f4-4abf-8fc5-66fda8537e06',57,'text','- **Trước khi điều trị (Xây móng an toàn)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bcdddb1e-f9d8-4730-96e3-11f991e973a8','0b36b210-b0f4-4abf-8fc5-66fda8537e06',58,'text','Tuyệt đối không để bệnh nhân ngồi lên ghế nha khi chưa hoàn tất bộ lọc kiểm duyệt thông tin và chuẩn bị hậu trường:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('740fde5e-a816-42d3-ba3c-2d0c884d1ad1','0b36b210-b0f4-4abf-8fc5-66fda8537e06',59,'text','- **Xác thực sự đồng thuận:** Kiểm tra lại trên CRM và xác nhận trực tiếp với bệnh nhân một lần nữa về phương án điều trị đã thống nhất (loại răng sứ nào, trụ implant gì, lộ trình nhổ răng ra sao).- **Minh bạch tài chính:** Đảm bảo khách hàng đã nắm rõ tổng chi phí, các khoản đã thanh toán hoặc tiến độ trả góp, không mập mờ về tiền bạc trước giờ G.- **Cam kết thời gian:** Thông báo trước cho bệnh nhân thời gian dự kiến của ca điều trị (Ví dụ: *"Ca phẫu thuật implant của anh hôm nay sẽ diễn ra trong khoảng 45 phút nhé ạ"*).- **Sàng lọc sức khỏe hiện tại:** Hỏi thăm và đo đạc lại các chỉ số huyết áp, tiểu đường (nếu cần), kiểm tra tình trạng ăn uống, ngủ nghỉ của bệnh nhân trước khi can thiệp y khoa.- **Rà soát hồ sơ & Trust Assets:** Bác sĩ bật sẵn phim chụp X-quang CT Cone Beam, kế hoạch điều trị hiển thị rõ ràng trên màn hình máy tính cạnh ghế nha.- **Khai thác điểm nhạy cảm:** Đọc kỹ ghi chú trên CRM để nhận diện các đặc tính riêng biệt của khách: khách có tiền sử sợ đau, dị ứng thuốc, từng có trải nghiệm nha khoa xấu trong quá khứ, hay đang có bệnh nền... để nhân sự có kịch bản ứng xử tinh tế.- **Chuẩn bị không gian vô trùng:** Trợ thủ set-up phòng điều trị sạch sẽ, mở gói dụng cụ vô trùng ngay trước mặt bệnh nhân để chứng minh tính an toàn cao nhất của Clinic System.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c9e42c9a-bbd2-4797-972f-0b17fc04f837','16-patient-experience','1112334e-95b7-4eb8-a2f9-6184d6ddc567',4,'Trong lúc điều trị (Nghệ thuật xoa dịu cảm xúc trên ghế nha)','trong-luc-ieu-tri-nghe-thuat-xoa-diu-cam-xuc-tren-ghe-nha',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('17402d04-6c3e-4a13-9789-d63d9de4227e','c9e42c9a-bbd2-4797-972f-0b17fc04f837',60,'text','Khi bệnh nhân đã nằm trên ghế răng và bị che mắt bởi kính bảo hộ, mọi tiếng động và lời nói của đội ngũ điều trị sẽ được phóng đại trong tâm trí họ. Do đó, toàn bộ ê-kíp phải tuân thủ kỷ luật giao tiếp:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a2be5a69-39cf-4481-8d0a-90c11da1392b','c9e42c9a-bbd2-4797-972f-0b17fc04f837',61,'text','- **Định hướng hành vi (Verbal Signaling):** Bác sĩ luôn giải thích ngắn gọn trước khi thực hiện một thao tác mới (Ví dụ: *"Bây giờ bác sĩ sẽ tiến hành bôi tê nhẹ để anh không thấy đau khi tiêm nhé", "Bác sĩ chuẩn bị dùng máy rung, tiếng máy sẽ hơi rè một chút nhưng hoàn toàn không đau đâu ạ"*).- **Dự báo cảm giác trước:** Báo trước các phản ứng sinh học tự nhiên mà bệnh nhân sắp trải qua để họ không bị giật mình hoảng sợ (Ví dụ: hơi mỏi hàm, có cảm giác tức nhẹ ở vùng xương, có dòng nước mát chảy qua).- **Tương tác và kiểm tra liên tục:** Cứ sau mỗi 5 - 10 phút, bác sĩ hoặc trợ thủ phải hỏi thăm bằng những câu hỏi đóng/mở tinh tế: *"Anh có thấy thoải mái không?", "Nếu có bất kỳ chỗ nào ê buốt, anh cứ giơ tay trái lên ra hiệu cho bác sĩ dừng lại nhé"*.- **Kiểm soát đau tuyệt đối:** Sử dụng các kỹ thuật gây tê tầng, đi kim chậm và theo dõi sát sao biểu cảm cơ mặt của khách hàng. Không cố làm khi bệnh nhân đang có dấu hiệu gồng mình chịu đau.- **Trợ thủ làm chủ bầu không khí:** Phụ tá không chỉ hút nước bọt mượt mà để khách không bị sặc, mà phải liên tục quan sát các dấu hiệu tâm lý như tay khách nắm chặt vào thành ghế, mồ hôi trán vã ra... để chủ động vỗ nhẹ vào vai trấn an khách.- **Kỷ luật phát ngôn nội bộ:** Tuyệt đối cấm trao đổi các câu chuyện phiếm cá nhân hoặc thảo luận về lỗi kỹ thuật, sự cố lâm sàng trước mặt bệnh nhân. Mọi lời nói giữa bác sĩ và trợ thủ phải ngắn gọn, chuyên nghiệp, liên quan trực tiếp đến ca làm để giữ sự uy nghiêm y khoa.- **Cập nhật tiến trình thời gian:** Đối với các ca điều trị kéo dài (như mài cùi răng sứ toàn hàm, chỉnh nha phức tạp), bác sĩ cần thông báo tiến độ để khách giải tỏa mệt mỏi: *"Chúng ta đã hoàn thành được 70% chặng đường rồi, anh/chị cố gắng thêm một chút nữa nhé"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d417d99f-6955-4f8b-90c2-5efe44137783','16-patient-experience','1112334e-95b7-4eb8-a2f9-6184d6ddc567',4,'Sau khi kết thúc điều trị (Đóng gói trải nghiệm và kiến tạo Wow Peak)','sau-khi-ket-thuc-ieu-tri-ong-goi-trai-nghiem-va-kien-tao-wow-peak',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('55c99fcc-8f0e-4abe-9c3c-644e421462ea','d417d99f-6955-4f8b-90c2-5efe44137783',62,'text','Khi bước xuống khỏi ghế răng, cảm xúc của bệnh nhân sẽ dịch chuyển từ trạng thái căng thẳng sang nhẹ nhõm nhẹ nhàng. Đây là thời điểm vàng để tạo ấn tượng sâu sắc:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bf6ca56f-bd5c-4fb0-bc74-585b60e355bb','d417d99f-6955-4f8b-90c2-5efe44137783',63,'text','- **Trực quan hóa kết quả (Wow Peak):** Cho bệnh nhân xem lại nụ cười mới, chiếc răng vừa trám hoặc phim chụp trụ implant đã nằm đúng vị trí trong xương hàm thông qua gương lớn hoặc màn hình. Hãy để họ tự trầm trồ về sự thay đổi ngoạn mục.- **Giải nghĩa y khoa tinh gọn:** Bác sĩ tóm tắt lại những gì vừa thực hiện thành công tốt đẹp, củng cố niềm tin cho khách hàng rằng ca điều trị đã diễn ra hoàn hảo.- **Cá nhân hóa cẩm nang hậu phẫu:** Trợ thủ hoặc bộ phận tư vấn hướng dẫn cực kỳ kỹ lưỡng về chế độ ăn uống (kiêng nóng, kiêng cay, ăn đồ mềm), cách vệ sinh răng miệng nhẹ nhàng tại vùng vừa can thiệp và cách chườm đá giảm sưng.- **Bàn giao đơn thuốc rõ ràng:** Gửi đơn thuốc (nếu có), giải thích rõ liều lượng, thời gian uống và các phản ứng phụ thông thường (như hơi nề nhẹ, râm ran ê) để khách chủ động tâm lý, không bị hoang mang khi về nhà.- **Khóa mục tiêu tái khám (Recall Booking):** Tuyệt đối không để khách ra về với lịch hẹn chung chung kiểu *"tháng sau qua anh khám lại"*. Phải chốt đích danh: Ngày - Giờ - Bác sĩ thực hiện ca tái khám/cắt chỉ/gắn răng tiếp theo.- **Đồng bộ hóa dữ liệu CRM:** Cập nhật ngay lập tức tình trạng điều trị thực tế, hình ảnh lâm sàng sau làm lên hệ thống CRM. Gắn tag chính xác mức độ nhạy cảm của ca (Ví dụ: `Completed_Implant_Stage1`, `High_Pain_Sensitivity_Monitor`) để bộ phận CSKH kích hoạt đường ống bám đuổi và hỏi thăm hậu phẫu vào buổi tối cùng ngày theo đúng tiêu chuẩn SLA của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('211339c0-28e8-4b0b-ae08-3898f611a735','16-patient-experience','7f9407b4-8bec-47f2-8767-147bb88a6bfc',3,'Giai đoạn 3 - CHĂM SÓC SAU ĐIỀU TRỊ: đường ống nuôi dưỡng cảm xúc và chiến lược phòng ngừa biến chứng','giai-oan-3-cham-soc-sau-ieu-tri-uong-ong-nuoi-duong-cam-xuc-va-chien-luoc-phong-',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a2d9ba05-75f2-4d92-9c62-7f528b5812c3','211339c0-28e8-4b0b-ae08-3898f611a735',64,'text','Một trong những sai lầm kinh điển nhất của các phòng khám nha khoa truyền thống là coi hành trình khách hàng kết thúc ngay khi bệnh nhân bước ra khỏi cửa sảnh và thanh toán xong hóa đơn. Trong hệ điều hành **Dental Empire OS**, chúng tôi định nghĩa lại điều này: **Khi bệnh nhân rời khỏi ghế nha, cuộc đua trải nghiệm thực sự mới bắt đầu.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ee45d614-e62e-4e55-ac96-a14c05418df7','211339c0-28e8-4b0b-ae08-3898f611a735',65,'text','Khi bước ra khỏi không gian phòng khám, bệnh nhân sẽ phải đối mặt với thực tế một mình. Thuốc tê hết tác dụng đồng nghĩa với việc những cơn đau nhẹ, cảm giác sưng tấy xuất hiện. Đi kèm với đó là hàng loạt sự lo lắng mơ hồ: *"Liệu triệu chứng này có bình thường không?", "Uống thuốc này trước hay sau khi ăn?", "Bị chảy máu nhẹ thế này có sao không?"*. Sự hoang mang này nếu không được xử lý kịp thời sẽ nhanh chóng chuyển hóa thành sự thất vọng và nghi ngờ năng lực của Bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('249c70d2-c8f6-4eda-ae30-0b578b518528','211339c0-28e8-4b0b-ae08-3898f611a735',66,'text','Ngược lại, nếu phòng khám chủ động chạm vào họ đúng lúc bằng một đường ống chăm sóc hậu phẫu hoàn hảo, bệnh nhân sẽ cảm thấy mình được bảo vệ, được tôn trọng như một con người. Đây chính là chìa khóa vàng để kích hoạt lòng biết ơn, chuẩn bị tâm lý cho lịch hẹn tái khám và tạo bệ phóng tuyệt vời cho hoạt động thu thập Review/Referral ở các bước tiếp theo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d2af2cfd-5f2b-4be3-bb3e-a993b3615c59','16-patient-experience','211339c0-28e8-4b0b-ae08-3898f611a735',4,'Mục tiêu quản trị cốt lõi của giai đoạn này được đúc kết qua công thức:','muc-tieu-quan-tri-cot-loi-cua-giai-oan-nay-uoc-uc-ket-qua-cong-thuc',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c456941-e2e6-4da4-9e9a-9ab4c282b7c4','d2af2cfd-5f2b-4be3-bb3e-a993b3615c59',67,'text','\\text{[Giảm lo lắng hậu phẫu]} + \\text{[Phát hiện sớm biến chứng]} + \\text{[Tăng chỉ số cảm được quan tâm]} = \\text{Bệ phóng hoàn hảo cho Tái khám \\& Review}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('367d769e-9eab-4708-939a-6fba9cb2b680','16-patient-experience','211339c0-28e8-4b0b-ae08-3898f611a735',4,'Timeline chăm sóc sau điều trị chuẩn đồng bộ (crm automation timeline)','timeline-cham-soc-sau-ieu-tri-chuan-ong-bo-crm-automation-timeline',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('23b3f8b1-2961-42b8-a6b9-ed8bbd2f0148','367d769e-9eab-4708-939a-6fba9cb2b680',68,'text','Để đảm bảo không một bệnh nhân nào bị bỏ quên và nhân sự không bị quá tải, quy trình chăm sóc hậu phẫu phải được lập trình theo dòng thời gian chuẩn xác trên hệ thống CRM với 4 mốc thời gian "vàng":',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ae2aae17-2493-4d26-b2b5-8265bf1db2a8','367d769e-9eab-4708-939a-6fba9cb2b680',69,'text','- **Mốc 1: Giờ vàng T + 2h (Ngay sau khi rời phòng khám)***Hình thức:* Tin nhắn tự động qua Zalo OA / Messenger.- *Mục đích:* Gửi cẩm nang số, dặn dò y khoa cứu cánh ngay khi thuốc tê chuẩn bị hết tác dụng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d3cfaca-ae0a-4c6e-ade0-3e96ca237919','367d769e-9eab-4708-939a-6fba9cb2b680',70,'text','- *Hình thức:* Bộ phận Patient Care gọi điện trực tiếp (hoặc nhắn tin cá nhân hóa đối với dịch vụ nhẹ).- *Mục đích:* Khảo sát mức độ đau, sưng, kiểm tra kỷ luật uống thuốc và phát hiện sớm các dấu hiệu bất thường để Bác sĩ kịp thời can thiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('527fb20b-2cf9-4cd3-a806-22b7d6dbc85d','367d769e-9eab-4708-939a-6fba9cb2b680',71,'text','- *Hình thức:* Tin nhắn hỏi thăm tiến độ lành thương.- *Mục đích:* Đo lường mức độ thuyên giảm của triệu chứng, xoa dịu tâm lý đối với các ca phẫu thuật lớn (Implant, nhổ răng khôn lệch, chỉnh nha diện rộng).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('efd15905-8617-4a45-9417-7da829b70402','367d769e-9eab-4708-939a-6fba9cb2b680',72,'text','- *Hình thức:* Tin nhắn xác nhận tự động kết hợp cuộc gọi của Lễ tân.- *Mục đích:* Nhắc nhở, giải thích giá trị của buổi tái khám và khóa mục tiêu Show-up.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3','16-patient-experience','211339c0-28e8-4b0b-ae08-3898f611a735',4,'Kịch bản mẫu nội dung chăm sóc sau điều trị chuyên nghiệp','kich-ban-mau-noi-dung-cham-soc-sau-ieu-tri-chuyen-nghiep',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5502806b-0309-40b9-984a-387b7113c043','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',73,'text','Dưới đây là bộ khung kịch bản tin nhắn đã được chuẩn hóa ngôn từ—vừa mang tính nghiêm túc của ngành y, vừa tràn đầy sự thấu cảm, sẵn sàng để lập trình vào hệ thống CRM Automation:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0cd61c74-3759-4ed9-8601-d51aba5aec87','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',74,'text','**Kịch bản gửi ngay sau điều trị (Mốc T + 2h)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f606bb50-a6d9-4833-9f69-91c3be6df94f','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',75,'text','**Bối cảnh sử dụng:** Hệ thống tự động kích hoạt gửi cho bệnh nhân sau khi trạng thái trên CRM chuyển sang `Completed` được 2 tiếng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('07fe9a8c-cd52-4697-b757-c97d359b4852','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',76,'text','"Chào anh/chị **[Tên_Bệnh_Nhân]**, hôm nay mình vừa hoàn tất phần điều trị dịch vụ **[Tên_Dịch_Vụ]** tại Nha khoa **[Tên_Phòng_Khám]**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9c1f1b05-22aa-4287-9d2b-83e14d8a8d10','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',77,'text','Hiện tại thuốc tê có thể đã bắt đầu hết tác dụng, để đảm bảo quá trình hồi phục diễn ra êm ái nhất, trong 24 giờ đầu anh/chị lưu ý giúp phòng khám:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3b3c0613-4f71-4dc9-be51-8a96ff72b52c','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',78,'text','- **Ăn uống nhẹ nhàng:** Ưu tiên đồ ăn mềm, nguội, lỏng (cháo, súp). Tránh nhai trực tiếp vào bên vừa điều trị.- **Tuân thủ đơn thuốc:** Uống thuốc đúng giờ và đúng liều lượng theo hướng dẫn chi tiết của Bác sĩ trong đơn.- **Phản ứng thông thường:** Nếu vùng điều trị có dấu hiệu đau nhẹ, ê buốt hoặc rỉ chút dịch màu hồng, anh/chị an tâm vì đây là phản ứng hoàn toàn bình thường của cơ thể ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8a70f953-6c41-40ec-b3d6-0ce22cc7b5dd','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',79,'text','*Lưu ý đặc biệt:* Nếu anh/chị gặp các dấu hiệu bất thường như đau nhức dữ dội không giảm sau khi uống thuốc, sưng lớn đột ngột hoặc chảy máu kéo dài, anh/chị hãy bấm gọi ngay Hotline **[Số_Hotline]** để được Bác sĩ hỗ trợ khẩn cấp 24/7 nhé ạ!"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('04d1c47a-e81c-42a7-9686-2dc7d771b716','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',80,'text','**Kịch bản gọi điện/nhắn tin hỏi thăm sau 24 giờ (Mốc T + 24h)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a3da4813-5d58-49e3-a58e-e42d5223410d','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',81,'text','**Bối cảnh sử dụng:** Nhân viên Patient Care lọc danh sách khách điều trị ngày hôm trước trên CRM để chủ động kết nối vào khung giờ cố định.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e75c2a74-4ba6-42de-af11-5b6d072f1bbf','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',82,'text','"Chào anh/chị **[Tên_Bệnh_Nhân]**, em là **[Tên_Nhân_Viên]** thuộc bộ phận Chăm sóc bệnh nhân của Nha khoa **[Tên_Phòng_Khám]** ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('07344a0a-82b1-426c-b24c-7d258346a0b4','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',83,'text','Em gọi điện/nhắn tin để hỏi thăm tình trạng răng miệng của mình sau ca điều trị ngày hôm qua thế nào rồi ạ? Hiện tại anh/chị có còn bị đau, ê buốt hay gặp khó khăn gì trong việc ăn uống và uống thuốc không anh/chị?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('be0ccc0a-cdff-48db-a9db-4699539bb69b','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',84,'text','Bác sĩ điều trị của anh/chị vẫn đang theo dõi sát sao hồ sơ này. Nếu anh/chị có bất kỳ câu hỏi nào, cứ chia sẻ ngay với em để em gửi thông tin cho Bác sĩ kiểm tra và hỗ trợ mình kịp thời nhé ạ."',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0a502f81-71ab-4491-b8a5-ee4415de1bff','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',85,'text','**Kịch bản nhắc lịch tái khám định kỳ / kiểm tra (Mốc T - 24h)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('52c42a20-6a4d-4fbc-8d3f-b0759bde8c94','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',86,'text','**Bối cảnh sử dụng:** Gửi trước ngày hẹn tái khám 1 ngày để sàng lọc và sắp xếp công suất ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4ad6d157-27cf-4471-a377-c5e8c05af4ed','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',87,'text','"Chào anh/chị **[Tên_Bệnh_Nhân]**, Nha khoa **[Tên_Phòng_Khám]** xin phép nhắc lịch hẹn tái khám của mình đã đặt trước vào lúc **[Giờ_Hẹn]** ngày **[Ngày_Hẹn]** ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2cacb8f3-5419-436c-a142-700640f20ad5','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',88,'text','**Thông tin lịch hẹn:**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a2bdc2c3-c0d4-4402-bd13-fa06546ff9fa','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',89,'text','- **Bác sĩ phụ trách:** Bác sĩ **[Tên_Bác_Sĩ]**- **Nội dung buổi hẹn:** Kiểm tra mức độ hồi phục ổn định của răng và tiến hành bước điều trị tiếp theo theo đúng phác đồ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('90fe25fb-f039-464c-be53-b7c11abec153','aa8ed1ac-fc4b-477a-a98f-d79f5c9f56d3',90,'text','Buổi tái khám này cực kỳ quan trọng để đảm bảo kết quả răng của anh/chị đạt độ bền và an toàn tối đa. Anh/chị xác nhận lại giúp phòng khám bằng cách phản hồi **''ĐỒNG Ý''** hoặc nhắn lại khung giờ khác nếu muốn thay đổi để em giữ ghế nha và chuẩn bị đón tiếp mình chu đáo nhất nhé ạ!"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2c38e984-8cef-4c07-9198-745a21102d72','16-patient-experience','7f9407b4-8bec-47f2-8767-147bb88a6bfc',3,'Giai đoạn 4 - TÁI KHÁM: trục xương sống giữ chân bệnh nhân và chiến lược khai thác giá trị vòng đời (LTV - Life Time Value)','giai-oan-4-tai-kham-truc-xuong-song-giu-chan-benh-nhan-va-chien-luoc-khai-thac-g',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('84238788-d39d-4ecf-8369-dbce2f1d664a','2c38e984-8cef-4c07-9198-745a21102d72',91,'text','Trong quản trị nha khoa truyền thống, buổi tái khám thường bị xem nhẹ như một thủ tục phụ trợ, thậm chí là một "chi phí" tốn thời gian của Bác sĩ khi không trực tiếp sinh ra doanh thu ngay lập tức. Nhưng trong hệ điều hành **Dental Empire OS**, chúng tôi định nghĩa một tư duy hoàn toàn trái ngược: **Tái khám chính là trục xương sống quyết định sự sống còn của phòng khám RHM, là mỏ neo giữ chân bệnh nhân trọn đời và là điểm chạm cốt lõi để gia tăng Giá trị vòng đời khách hàng (Lifetime Value - LTV).**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0eae0068-0ba2-419b-9347-6c7fd9cac48f','2c38e984-8cef-4c07-9198-745a21102d72',92,'text','Buổi tái khám vượt ra khỏi ranh giới của một cuộc kiểm tra y khoa thuần túy. Đây là thời điểm vàng để phòng khám chứng minh cam kết trách nhiệm đi đến cùng với nụ cười của bệnh nhân. Đây là nơi chúng ta củng cố niềm tin tuyệt đối, giải quyết triệt để những băn khoăn hay triệu chứng phát sinh trong quá trình lành thương, và trực quan hóa kết quả điều trị thành công.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6544bcf3-5036-418b-89fd-a986584faae4','2c38e984-8cef-4c07-9198-745a21102d72',93,'text','Khi bệnh nhân nhìn thấy sự tận tụy của đội ngũ và sự biến đổi kỳ diệu của hàm răng, chỉ số hạnh phúc của họ sẽ đạt đỉnh. Chính mốc cảm xúc này sẽ mở toang cánh cửa để phòng khám thu hoạch những tài sản vô giá: những bài đánh giá 5 sao rực rỡ và những lời giới thiệu chất lượng cao đến từ người thân, bạn bè của họ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('255116f8-19f4-4212-a374-b110032959e1','16-patient-experience','2c38e984-8cef-4c07-9198-745a21102d72',4,'Mục tiêu chiến lược của giai đoạn Tái khám được đúc kết qua công thức vận hành sau:','muc-tieu-chien-luoc-cua-giai-oan-tai-kham-uoc-uc-ket-qua-cong-thuc-van-hanh-sau',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('521026cb-bf4a-43de-900d-c2316977a4d9','255116f8-19f4-4212-a374-b110032959e1',94,'text','\\text{[Đảm bảo kết quả điều trị lâm sàng]} + \\text{[Gia tăng chỉ số hạnh phúc]} + \\text{[Duy trì sợi dây liên kết bền vững]} = \\text{Khơi thông dòng chảy Review \\& Referral}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('49575c80-4533-4007-a829-76073e3c7391','255116f8-19f4-4212-a374-b110032959e1',95,'image',NULL,'book/16-patient-experience/56e47232-344f-4f8c-aea5-b7bbc602eaec-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('73b9a9e2-cd51-4ea0-bf12-41bcad196b1a','16-patient-experience','2c38e984-8cef-4c07-9198-745a21102d72',4,'Checklist vận hành trải nghiệm tái khám tiêu chuẩn','checklist-van-hanh-trai-nghiem-tai-kham-tieu-chuan',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a5b1558b-f0aa-4857-b1ef-599f045b68b2','73b9a9e2-cd51-4ea0-bf12-41bcad196b1a',96,'text','Để biến mỗi buổi tái khám thành một trải nghiệm thắt chặt mối quan hệ bền vững, toàn bộ bộ máy vận hành từ Lễ tân, Trợ thủ cho đến Bác sĩ điều trị phải thực thi nghiêm ngặt bộ checklist hành động dưới đây:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2984d9e6-77fc-49b0-bb75-8da55ea87ec1','16-patient-experience','73b9a9e2-cd51-4ea0-bf12-41bcad196b1a',5,'Trước khi buổi tái khám diễn ra (Hậu trường chuẩn bị dữ liệu)','truoc-khi-buoi-tai-kham-dien-ra-hau-truong-chuan-bi-du-lieu',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3513bc17-cd3c-4ff1-8f7b-d4e3e34303e6','2984d9e6-77fc-49b0-bb75-8da55ea87ec1',97,'text','Nguyên tắc tối thượng là **không để Bác sĩ bước vào phòng khám với một cái đầu rỗng**. Bệnh nhân cực kỳ ghét việc phải lặp lại tình trạng của mình cho một ê-kíp hay quên. Do đó, khâu chuẩn bị dữ liệu là bắt buộc:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6651ce77-ff44-4bbd-ad63-17f978150a0b','2984d9e6-77fc-49b0-bb75-8da55ea87ec1',98,'text','- **Nhắc lịch chuẩn SLA:** Đội ngũ CSKH hoặc hệ thống tự động gửi tin nhắn/gọi điện nhắc lịch trước 24 giờ để sàng lọc công suất ghế nha.- **Khóa mục tiêu Show-up:** Đảm bảo bệnh nhân đã phản hồi xác nhận chắc chắn đến đúng giờ, hoặc kịp thời sắp xếp lại khung giờ khác nếu khách gặp sự cố đột xuất.- **Trích xuất dữ liệu CRM:** Trợ thủ có nhiệm vụ mở hồ sơ điện tử, kiểm tra kỹ nhật ký điều trị của ca hẹn trước khi bệnh nhân bước vào phòng (Họ làm dịch vụ gì ở buổi trước? Có gặp tình trạng nhạy cảm hay đau nhức gì khi về nhà không?).- **Chuẩn bị tư liệu trực quan:** Bật sẵn các file phim chụp X-quang cũ, hình ảnh lâm sàng Before (trước khi làm) và các ghi chú tâm lý của bệnh nhân lên màn hình hiển thị tại ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c16d2083-daaf-496a-92ac-abae81668296','16-patient-experience','73b9a9e2-cd51-4ea0-bf12-41bcad196b1a',5,'Trong buổi tái khám (Nghệ thuật đối thoại và trực quan hóa kết quả)','trong-buoi-tai-kham-nghe-thuat-oi-thoai-va-truc-quan-hoa-ket-qua',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fd1ce1c9-17dd-4a52-bc59-b3702cdea941','c16d2083-daaf-496a-92ac-abae81668296',99,'text','Khi bệnh nhân ngồi lên ghế răng, Bác sĩ không lao vào khám ngay mà phải thực hiện quy trình đối thoại thấu cảm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3d2cf97b-25ac-4e36-b069-1f1a6cb29bfc','c16d2083-daaf-496a-92ac-abae81668296',100,'text','- **Lắng nghe cảm nhận thực tế:** Bác sĩ chủ động hỏi thăm trải nghiệm của bệnh nhân khi ở nhà: *"Sau buổi làm hôm trước về anh/chị ăn uống có tốt không? Răng có bị ê buốt hay gặp khó chịu ở vị trí nào không?"*.- **Đánh giá tốc độ hồi phục:** Tiến hành thăm khám lâm sàng tỉ mỉ để kiểm tra mức độ lành thương của mô nướu, độ ổn định của trụ implant, khớp cắn của răng sứ hoặc tiến trình dịch chuyển của răng niềng.- **Trực quan hóa sự biến đổi (The Contrast Effect):** Đây là bước tối quan trọng. Bệnh nhân thường có xu hướng "quên" mất hàm răng của mình từng tệ thế nào. Bác sĩ phải chụp lại ảnh hiện tại, đặt cạnh hình ảnh Before trước đây trên màn hình lớn để khách hàng nhìn thấy sự khác biệt rõ rệt. Sự tương phản trực quan này chính là chất xúc tác mạnh nhất tạo ra cảm xúc "Wow".- **Giải thích tiến trình hiện tại:** Bác sĩ giải thích cặn kẽ kết quả hồi phục hiện tại đang tốt đẹp ra sao bằng ngôn ngữ đại chúng, giúp bệnh nhân an tâm tuyệt đối.- **Tinh chỉnh lâm sàng kịp thời:** Tiến hành các thao tác mài chỉnh khớp cắn, vệ sinh vùng quanh răng hoặc siết dây cung nhẹ nhàng, êm ái nếu có điểm bất tiện nhỏ phát sinh.- **Ghi nhận chỉ số hài lòng:** Lắng nghe và đánh giá mức độ hài lòng thực tế của bệnh nhân bằng thang đo cảm xúc để cập nhật vào CRM.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('53a21862-6607-42e5-85a4-639a51722dd6','16-patient-experience','73b9a9e2-cd51-4ea0-bf12-41bcad196b1a',5,'Sau khi kết thúc buổi tái khám (Phân loại dữ liệu và kích hoạt lan tỏa)','sau-khi-ket-thuc-buoi-tai-kham-phan-loai-du-lieu-va-kich-hoat-lan-toa',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2e3291ed-44c3-45d0-bd03-56835aa42195','53a21862-6607-42e5-85a4-639a51722dd6',101,'text','Khi bệnh nhân bước xuống ghế nha với sự hài lòng tuyệt đối, đây là lúc bộ máy Growth Engine chuyển trạng thái thu hoạch:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dcea6065-a559-4df4-8482-76c4c3d4b9af','53a21862-6607-42e5-85a4-639a51722dd6',102,'text','- **Số hóa nhật ký tái khám:** Cập nhật ngay kết quả buổi khám, hình ảnh mới nhất và tiến độ điều trị lên hệ thống CRM.- **Gửi lời cảm ơn & Tư liệu số:** Hệ thống tự động gửi một tin nhắn cảm ơn bệnh nhân đã tin tưởng đồng hành, kèm theo file hình ảnh Before - After (nếu phù hợp) để họ có thể tự hào lưu lại hoặc chia sẻ lên trang cá nhân.- **Khóa chu kỳ bảo dưỡng (Recall Booking):** Lễ tân tiến hành hẹn lịch cho buổi duy trì, cạo vôi răng định kỳ 6 tháng tiếp theo để bảo vệ kết quả điều trị bền vững.- **Phân loại tệp xin Review:** Nếu khách hàng được ghi nhận ở mức độ hài lòng rất cao (`High_Satisfaction`), gắn tag hệ thống để chuyển dữ liệu sang bộ phận CSKH thực hiện quy trình xin đánh giá 5 sao trên Google Maps hoặc quay video Testimonial.- **Phân loại tệp kích hoạt Referral:** Định danh những bệnh nhân trung thành, yêu mến phòng khám để đưa vào chương trình Đại sứ thương hiệu, tặng họ các voucher tầm soát răng miệng miễn phí để họ chủ động trao tặng và giới thiệu cho người thân, bạn bè.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('96ab7918-b151-48e3-957a-b4534c49bb2a','53a21862-6607-42e5-85a4-639a51722dd6',103,'text','** SLA là viết tắt của Service Level Agreement, nghĩa là cam kết mức độ dịch vụ.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('acf6418d-5652-4818-b8d8-7e875abd5667','16-patient-experience','7f9407b4-8bec-47f2-8767-147bb88a6bfc',3,'Giai đoạn 5 - REVIEW: Chiến lược số hóa lòng biết ơn và thu hoạch tài sản niềm tin (Trust Assets)','giai-oan-5-review-chien-luoc-so-hoa-long-biet-on-va-thu-hoach-tai-san-niem-tin-t',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6aeb197f-a67d-4e7f-84da-8fe79ffa4047','acf6418d-5652-4818-b8d8-7e875abd5667',104,'text','Trong hệ điều hành **Dental Empire OS**, tôi không bao giờ coi một bài đánh giá (Review) trên Google Maps hay Facebook là một thứ đồ trang trí cho đẹp trang trí. Review chính là loại **Tài sản niềm tin (Trust Assets)** có giá trị thương mại và sức mạnh chuyển đổi cao nhất của phòng khám RHM.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('01973be2-8692-4450-8d4f-e481f646f821','acf6418d-5652-4818-b8d8-7e875abd5667',105,'text','Một quảng cáo hay đến đâu cũng chỉ là lời nói một chiều từ phía phòng khám, nhưng một dòng nhận xét chân thực từ một bệnh nhân bằng xương bằng thịt lại có sức nặng đập tan mọi pháo đài hoài nghi của người lạ. Khi chúng ta biến được sự hài lòng thầm lặng của bệnh nhân thành các tư liệu số công khai, chúng ta đang trực tiếp kích hoạt một cỗ máy tăng trưởng tự thân bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7512a947-6723-4db9-bb4c-2537e3de47b7','16-patient-experience','acf6418d-5652-4818-b8d8-7e875abd5667',4,'Mục tiêu chiến lược của Review','muc-tieu-chien-luoc-cua-review',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7ba54868-c645-4042-ba5d-4b48080838fd','7512a947-6723-4db9-bb4c-2537e3de47b7',106,'text','\\text{[Trust]} + \\text{[Authority]} + \\text{[Search Visibility]} + \\text{[Conversion Rate]} + \\text{[Referral]} = \\text{Cỗ máy tăng trưởng tự thân}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a61f88e8-c4ad-48a5-8883-d413309349a3','7512a947-6723-4db9-bb4c-2537e3de47b7',107,'text','Từ một bệnh nhân hạnh phúc, hệ thống trải nghiệm sẽ thu hoạch được:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('879e9266-d739-4619-bb53-5487a63b0f17','7512a947-6723-4db9-bb4c-2537e3de47b7',108,'text','- **Đánh giá 5 sao trên Google Maps:** Đẩy mạnh thứ hạng hiển thị ở tầng *Search Layer*, giúp phòng khám đè bẹp đối thủ khi khách gõ từ khóa "nha khoa gần đây".- **Feedback trực quan trên Facebook/TikTok:** Làm mồi nhử niềm tin tuyệt vời cho tầng *Traffic* và *Trust*.- **Video Testimonial chất lượng cao:** Vũ khí tối thượng để đội Sales gửi cho các lead đang do dự ở tầng *Conversion*.- **Tư liệu Case lâm sàng chuẩn hóa:** Minh chứng sống động cho năng lực thực tế của bộ máy *Clinic System*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3d7b3a71-27b2-488e-bddd-4fd1c0964823','16-patient-experience','acf6418d-5652-4818-b8d8-7e875abd5667',4,'"Thời điểm vàng" để kích hoạt lời mời xin review','thoi-iem-vang-e-kich-hoat-loi-moi-xin-review',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e729dd60-5eff-4e9f-a0ed-f2f03312ee14','3d7b3a71-27b2-488e-bddd-4fd1c0964823',109,'text','Sai lầm lớn nhất của nhân viên là xin review một cách máy móc theo kiểu phát tờ rơi, hoặc đưa QR code bắt khách quét khi họ đang vội vã ra về hoặc tâm trạng đang trung tính. Niềm tin và lòng biết ơn là những trạng thái cảm xúc có "điểm rơi". Bạn bắt buộc phải bắt trúng cái gọi là **Mốc cảm xúc đỉnh cao (Wow Peak)** của bệnh nhân để ngỏ lời:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('51b27ec0-9e9f-40bf-905e-21520f23ee8b','3d7b3a71-27b2-488e-bddd-4fd1c0964823',110,'text','- **Mốc 1: Khoảnh khắc soi gương hoàn thiện:** Ngay giây phút Bác sĩ tháo niềng răng, gắn hoàn chỉnh bộ răng sứ thẩm mỹ, hay lắp xong chiếc răng gắn trên trụ Implant. Khi bệnh nhân nhìn vào gương và vỡ òa hạnh phúc trước diện mạo mới của mình - đây là thời điểm vàng số 1.- **Mốc 2: Buổi tái khám lành thương hoàn hảo:** Khi bệnh nhân quay lại sau 1-2 tuần phẫu thuật hoặc nhổ răng khôn, họ hồ hởi thông báo: *"Về nhà không đau chút nào bác sĩ ạ, ăn nhai bình thường rồi"*. Lòng biết ơn của họ đang ở mức cao nhất.- **Mốc 3: Tiếng khen tự phát tại quầy lễ tân:** Khi bệnh nhân bước xuống thanh toán và chủ động nói với lễ tân: *"Bác sĩ ở đây làm mát tay quá em ạ, nhẹ nhàng mà nhiệt tình dã man"*. Nhân viên phải lập tức bắt lấy khoảnh khắc này để chuyển hóa thành review số.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c0c37f14-40af-4eb3-992e-6fc8625e9d1f','16-patient-experience','acf6418d-5652-4818-b8d8-7e875abd5667',4,'Kịch bản thu hoạch review tinh tế và chuẩn y khoa','kich-ban-thu-hoach-review-tinh-te-va-chuan-y-khoa',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7a00cbbd-61ec-44d6-81a3-3219e8766d33','c0c37f14-40af-4eb3-992e-6fc8625e9d1f',111,'text','Tuyệt đối không ép buộc hay làm khách hàng khó xử. Lời mời xin review phải được diễn đạt như một sự nhờ vả chân thành, hướng tới giá trị cộng đồng và mang lại niềm tự hào cho đội ngũ y bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b4fdfd91-b970-46d1-ae63-cde0dd835a79','16-patient-experience','c0c37f14-40af-4eb3-992e-6fc8625e9d1f',5,'Kịch bản xin review trực tiếp tại quầy (Dành cho Lễ tân / CSKH)','kich-ban-xin-review-truc-tiep-tai-quay-danh-cho-le-tan-cskh',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3433bc21-05b5-4050-8f16-3d0cd08d6887','b4fdfd91-b970-46d1-ae63-cde0dd835a79',112,'text','**Bối cảnh:** Khách vừa khen ngợi dịch vụ hoặc vừa hoàn thành ca điều trị xuất sắc tại ghế răng bước xuống quầy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fec790b5-690d-4216-8dc7-c027c3a5720c','b4fdfd91-b970-46d1-ae63-cde0dd835a79',113,'text','"Dạ, em rất vui khi nghe anh/chị **[Tên_Khách_Hàng]** chia sẻ như vậy ạ. Thấy anh/chị ăn nhai thoải mái và hài lòng với nụ cười mới, cả ê-kíp Bác sĩ bên em ngày hôm nay đều cảm thấy cực kỳ hạnh phúc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('05990efa-003c-43bc-85aa-1b76a00e2462','b4fdfd91-b970-46d1-ae63-cde0dd835a79',114,'text','Anh/chị ơi, những chia sẻ thực tế này của anh/chị chính là nguồn động lực lớn nhất của tụi em. Nếu không phiền, em xin phép nhờ anh/chị dành ra khoảng 1 phút quét mã QR này để lại một đánh giá ngắn trên Google Maps giúp phòng khám được không ạ? Những dòng nhận xét chân thực của anh/chị sẽ là lời bảo chứng giúp cho những bệnh nhân khác đang bị đau răng hoặc sợ đau ngoài kia có thêm sự an tâm để lựa chọn một nha khoa tử tế như bên em ạ."',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('333f88c2-957b-4216-a61d-04ae7d94b20f','16-patient-experience','c0c37f14-40af-4eb3-992e-6fc8625e9d1f',5,'Kịch bản nhắn tin chăm sóc kết hợp xin review qua Zalo OA','kich-ban-nhan-tin-cham-soc-ket-hop-xin-review-qua-zalo-oa',44,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ea809d3-b642-4552-b788-74f9c9bddb39','333f88c2-957b-4216-a61d-04ae7d94b20f',115,'text','**Bối cảnh:** Gửi sau buổi tái khám thành công tốt đẹp 2 tiếng để khách hàng thong thả thực hiện tại nhà.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f8dc256d-61ba-4f78-8e47-9175af8d01df','333f88c2-957b-4216-a61d-04ae7d94b20f',116,'text','"Chào anh/chị **[Tên_Khách_Hàng]**, Nha khoa **[Tên_Phòng_Khám]** xin gửi lời cảm ơn chân thành vì anh/chị đã tin tưởng và đồng hành cùng đội ngũ Bác sĩ trong suốt hành trình điều trị **[Tên_Dịch_Vụ]** vừa qua ạ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6904e749-bd27-40e5-8183-8cba48dc23a0','333f88c2-957b-4216-a61d-04ae7d94b20f',117,'text','Nếu anh/chị cảm thấy hài lòng với chất lượng chuyên môn cũng như sự chăm sóc của các bạn nhân viên, phòng khám rất mong sẽ nhận được một lời chia sẻ, đánh giá ngắn của anh/chị trên trang Google Maps chính thức của chúng em tại đường link này nhé ạ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f1688715-00f6-4d03-a8e3-24461938d75a','333f88c2-957b-4216-a61d-04ae7d94b20f',118,'text','🔗 **[Đường_Link_Google_Maps_Của_Phòng_Khám]**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8422111d-0262-4ae6-8627-2e32a8b2a81f','333f88c2-957b-4216-a61d-04ae7d94b20f',119,'text','Mỗi dòng góp ý của anh/chị vừa là phần thưởng tinh thần cho tập thể phòng khám, vừa giúp chúng em không ngừng hoàn thiện để phục vụ cộng đồng ngày một tốt hơn. Em cảm ơn anh/chị rất nhiều và chúc anh/chị luôn tràn ngập niềm vui với nụ cười mới ạ!"',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('34ca6442-e16f-45af-86ff-e0fe60341147','16-patient-experience','c0c37f14-40af-4eb3-992e-6fc8625e9d1f',5,'Công thức định hướng nội dung - Bí quyết tạo nên những "Review Triệu Đô"','cong-thuc-inh-huong-noi-dung-bi-quyet-tao-nen-nhung-review-trieu-o',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('25154094-84aa-4409-8aa8-b1aa06f7ff34','34ca6442-e16f-45af-86ff-e0fe60341147',120,'text','Một lỗi phổ biến là khách hàng chỉ viết chung chung: *"Nha khoa tốt, phục vụ nhiệt tình, 5 sao"*. Những review này rất nghèo thông tin và không có giá trị thuyết phục cao ở tầng Search/Trust. Bạn không được viết sẵn bài giả cho khách (vi phạm tính trung thực y khoa), nhưng nhân viên tư vấn có thể khéo léo gợi ý họ chia sẻ theo **Công thức 5 tầng câu hỏi**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cd214583-2a0a-4cdd-9385-6559eafb4a9f','34ca6442-e16f-45af-86ff-e0fe60341147',121,'text','*"Anh/chị ơi, khi viết đánh giá, anh/chị có thể chia sẻ ngắn gọn dựa theo mấy ý này để những người đọc sau dễ hình dung nhất nhé ạ:"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9bf0ae24-8e47-4fc5-8f0a-a6d3ee1968c8','34ca6442-e16f-45af-86ff-e0fe60341147',122,'text','- **Nỗi đau ban đầu:** Trước khi đến đây, răng của anh/chị gặp tình trạng khó chịu gì? (Kích hoạt từ khóa bệnh lý cho SEO).- **Ấn tượng về con người:** Anh/chị cảm thấy thái độ và tay nghề của Bác sĩ điều trị trực tiếp như thế nào?- **Cảm giác thực tế:** Quá trình làm trên ghế răng có bị đau hay đáng sợ như anh/chị từng lo lắng không?- **Hậu trường chăm sóc:** Các bạn nhân viên gọi điện hỏi thăm, dặn dò hậu phẫu có chu đáo không?- **Kết quả hiện tại:** Anh/chị cảm thấy thế nào về chức năng ăn nhai và thẩm mỹ nụ cười hiện tại của mình?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6bb90118-6225-4ae6-8d14-cf8f9967fe57','34ca6442-e16f-45af-86ff-e0fe60341147',123,'text','Những bài đánh giá tuân thủ công thức này sẽ tự động chứa các từ khóa tự nhiên, biến thành những câu chuyện truyền cảm hứng mạnh mẽ, trực tiếp chuyển hóa những người lạ đang hoài nghi ở tầng Search Layer trở thành những lead nóng rực, sẵn sàng nhấc máy đặt lịch hẹn khám với hệ thống của bạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ef532efc-87a3-4571-b0cb-80b4d52f6762','16-patient-experience',NULL,2,'16.6 Trải nghiệm nào tạo ra sự quay lại?','166-trai-nghiem-nao-tao-ra-su-quay-lai',46,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6cbbb6a1-c901-42ec-b093-f9ff6f3da66f','ef532efc-87a3-4571-b0cb-80b4d52f6762',124,'text','Trong ngành nha khoa, để bệnh nhân đồng ý xuống tiền điều trị một ca lớn đã khó, nhưng để họ tự nguyện quay lại tái khám định kỳ, cạo vôi răng, hoặc tiếp tục thực hiện các phân hệ điều trị khác lại là một bài toán cân não hơn nhiều. Nhiều phòng khám lầm tưởng rằng "chỉ cần chữa hết đau là khách sẽ quay lại". Thực tế, bệnh nhân quay lại không phải vì chiếc răng đã được chữa xong, mà vì **họ nhớ cảm giác an tâm khi ở bên bạn**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf215b43-7468-4a67-9ce2-8d63aa271f93','ef532efc-87a3-4571-b0cb-80b4d52f6762',125,'text','Dưới đây là 4 loại trải nghiệm cốt lõi kích hoạt cơ chế quay lại (Retention/Recall) của bệnh nhân:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('460977df-9a94-42fd-9a68-75a3944ad0fd','ef532efc-87a3-4571-b0cb-80b4d52f6762',126,'text','- **Trải nghiệm về sự trung thực (Zero-Exploitation Experience):** Bệnh nhân cực kỳ nhạy cảm với việc bị "vẽ bệnh" hoặc chèo kéo mua thêm dịch vụ. Khi họ nhận được một phác đồ tư vấn trung thực, chỉ rõ cái gì cần làm ngay, cái gì có thể theo dõi thêm mà không hề bị ép uổng, một sợi dây an toàn tâm lý được thiết lập. Họ quay lại vì biết nơi này bảo vệ ví tiền và sức khỏe của họ.- **Trải nghiệm triệt tiêu ký ức đau (Pain-Free Memory):** Nỗi sợ đau là rào cản lớn nhất khiến khách hàng trì hoãn việc đi khám răng. Nếu phòng khám vận hành tốt quy trình kiểm soát đau (từ kỹ thuật bôi tê, tiêm tê tầng, thao tác êm ái của Bác sĩ đến sự dỗ dành của trợ thủ), bạn đã xóa bỏ được "bóng ma tâm lý" của họ. Khi cần làm chiếc răng tiếp theo, não bộ của họ sẽ tự động định vị bạn là nơi an toàn nhất.- **Trải nghiệm "Không bị bỏ rơi" hậu phẫu (Proactive Care):** Khoảnh khắc thuốc tê hết tác dụng tại nhà là lúc bệnh nhân dễ tổn thương và hoang mang nhất. Một cuộc gọi hỏi thăm đúng 8h tối từ bộ phận Patient Care, hay một tin nhắn dặn dò y khoa tự động xuất hiện đúng lúc họ cần sẽ tạo nên một trải nghiệm cảm xúc cực mạnh. Sự chủ động này biến mối quan hệ thương mại thành mối quan hệ gia đình.- **Trải nghiệm trực quan hóa tiến trình (Visual Progress Tracking):** Bệnh nhân luôn muốn nhìn thấy đồng tiền mình bỏ ra mang lại kết quả gì. Việc Bác sĩ chụp ảnh, mở phim, đặt hai bức ảnh Before – After cạnh nhau trong mỗi buổi tái khám để chỉ rõ: *"Răng của anh/chị đã hồi phục được 40% ở vùng này, xương hàm đang tích hợp rất tốt..."* giúp họ nhìn thấy quả ngọt. Họ quay lại vì họ muốn đi hết hành trình thành công đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4292808a-f8cf-4611-8227-97613b336991','16-patient-experience',NULL,2,'16.7 Trải nghiệm nào tạo ra sự giới thiệu?','167-trai-nghiem-nao-tao-ra-su-gioi-thieu',47,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b8701f08-b11a-4383-91d3-eb83203c19a2','4292808a-f8cf-4611-8227-97613b336991',127,'text','Một bệnh nhân hài lòng sẽ im lặng quay lại, nhưng một bệnh nhân được trải nghiệm sự "kinh ngạc" (Wow Peak) mới chủ động đi giới thiệu (Referral) cho người khác. Nha khoa là ngành có chi phí thu mua khách hàng (CAC) rất cao, do đó, dòng khách truyền miệng chính là nguồn lợi nhuận thuần túy nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6fcda27c-a132-45a5-b740-56a9a424c7a3','4292808a-f8cf-4611-8227-97613b336991',128,'text','Để biến một bệnh nhân thành một "đại sứ thương hiệu" không lương, bạn phải thiết kế được những trải nghiệm mang tính kích hoạt sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2e8b0eef-73ef-4640-92b2-8d0261dd1fae','4292808a-f8cf-4611-8227-97613b336991',129,'text','- **Trải nghiệm "Lột xác" ngoạn mục (The Metamorphosis):** Đối với các dịch vụ thẩm mỹ như niềng răng, răng sứ, hay cấy implant toàn hàm, kết quả không chỉ là hàm răng đều mà là sự thay đổi hoàn toàn diện mạo và sự tự tin của một con người. Khi bạn tạo ra một nụ cười xuất sắc khiến bạn bè, đồng nghiệp của bệnh nhân phải thốt lên: *"Dạo này làm gì mà xinh thế?"*, bạn đã gián tiếp cài cắm một biển quảng cáo di động. Bệnh nhân sẽ hào hứng chia sẻ tên phòng khám như một niềm tự hào.- **Trải nghiệm cá nhân hóa vượt mong đợi (Hyper-Personalization):** Khi một bệnh nhân bước vào và thấy từ bác bảo vệ đến lễ tân đều nhớ rõ tên mình, nhớ cả việc mình sợ tiếng máy khoan, hay nhớ buổi trước mình thích uống nước ấm thay vì nước lạnh... họ sẽ bị chinh phục hoàn toàn. Họ nhận ra mình không phải là một "mã bệnh nhân" trên CRM, mà là một vị khách quý. Sự trân quý này thúc đẩy họ muốn người thân của mình cũng được tận hưởng dịch vụ đẳng cấp đó.- **Sở hữu "Tài sản kiêu hãnh" (Social Capital Asset):** Con người có xu hướng chia sẻ những điều khiến họ trông có vẻ thông minh, xinh đẹp hoặc có gu hơn trên mạng xã hội. Khi phòng khám đóng gói hành trình của họ thành những thước phim Before/After chỉn chu, những bức ảnh chụp nụ cười rạng rỡ với ánh sáng studio chuyên nghiệp và gửi tặng họ, bạn đang trao cho họ một "tài sản kiêu hãnh". Họ đăng lên trang cá nhân để khoe, và đó chính là lúc dòng traffic referral tự nhiên đổ về.- **Cơ chế trao tặng tinh tế (The Benefactor Experience):** Thay vì giảm giá hoặc trả tiền hoa hồng thô thiển theo kiểu đa cấp (khiến bệnh nhân mang cảm giác mình đang "bán đứng" người quen), hệ thống trải nghiệm sẽ cung cấp các đặc quyền trao tặng. Ví dụ: *"Phòng khám gửi tặng riêng anh 3 suất tầm soát răng miệng chuyên sâu trị giá 1 triệu đồng để anh chủ động dành tặng cho những người thân yêu nhất của mình"*. Lúc này, bệnh nhân đi giới thiệu với vị thế của một người ban ơn, một người chia sẻ giá trị tử tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6947d6e9-69ef-4829-9205-021f31267be1','16-patient-experience',NULL,2,'16.8 Patient Experience như một hệ thống vận hành, không chỉ là thái độ phục vụ','168-patient-experience-nhu-mot-he-thong-van-hanh-khong-chi-la-thai-o-phuc-vu',48,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('afe7375a-ea12-438c-8ed5-8b6f5f19ec6f','6947d6e9-69ef-4829-9205-021f31267be1',130,'text','Đây là chương nhận thức quan trọng nhất trong Ebook này. 95% các chủ phòng khám tại Việt Nam khi nghe đến "Trải nghiệm khách hàng" hoặc "Dịch vụ khách hàng" thì ngay lập tức nghĩ đến việc: đào tạo lễ tân biết cúi chào, nhắc phụ tá biết cười tươi, bảo bác sĩ nói chuyện nhẹ nhàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3838476f-1cfe-4af7-b9b8-711fc6265552','6947d6e9-69ef-4829-9205-021f31267be1',131,'text','**Sai lầm chí mạng:** Xây dựng trải nghiệm dựa trên thái độ con người là cách làm nguyên thủy và kém bền vững nhất. Thái độ phục vụ là một **biến số**, còn Hệ thống vận hành phải là một **hằng số**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('896321d8-3d2e-463c-bc3f-be06b15935a0','6947d6e9-69ef-4829-9205-021f31267be1',132,'text','Nếu bạn chỉ dựa vào thái độ, trải nghiệm của bệnh nhân sẽ trồi sụt theo tâm trạng của nhân sự. Hôm nào lễ tân vui thì khách được tiếp đón niềm nở, hôm nào bác sĩ cãi nhau với người yêu thì ca lâm sàng đó trở nên lạnh lùng, u ám. Đó không phải là cách vận hành của một doanh nghiệp nha khoa thực chiến.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9301c28b-8a69-4f3d-8933-251e39e2f531','6947d6e9-69ef-4829-9205-021f31267be1',133,'text','Trong **Dental Empire OS**, Patient Experience là một **Hệ thống vận hành có lập trình, có cấu trúc dữ liệu, có chỉ số đo lường và có khả năng tự động hóa**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ac00130b-3e6a-4e37-a2cd-87d28f26dd08','6947d6e9-69ef-4829-9205-021f31267be1',134,'image',NULL,'book/16-patient-experience/42d7a76b-1687-494d-8a7f-9179b63fda51-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bf939aa1-f693-4841-b78d-238d756d5807','6947d6e9-69ef-4829-9205-021f31267be1',135,'text','Hệ thống vận hành trải nghiệm được định hình qua 4 trụ cột thép:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('91d5984c-a4ae-467b-81d2-e6b3f738fd8d','16-patient-experience','6947d6e9-69ef-4829-9205-021f31267be1',4,'Tiêu chuẩn hóa bằng SOP và SLA cứng','tieu-chuan-hoa-bang-sop-va-sla-cung',49,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('52d1de18-082f-497b-acba-f33e012f33a3','91d5984c-a4ae-467b-81d2-e6b3f738fd8d',136,'text','Mọi hành động cảm xúc đều được quy đổi thành quy trình kỹ thuật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a294651c-88c5-4874-af3f-43339d4b9a4a','91d5984c-a4ae-467b-81d2-e6b3f738fd8d',137,'text','- Không nói "Lễ tân phải trả lời tin nhắn nhanh", mà quy định rõ: **SLA phản hồi tin nhắn đầu tiên trên Messenger/Zalo dưới 5 phút.**- Không nói "Bảo vệ phải nhiệt tình", mà quy định: **Khi có tiếng còi xe ô tô, bảo vệ phải có mặt tại cửa xe trong vòng 10 giây để che ô cho khách.**- Không nói "Nhà vệ sinh phải sạch", mà thiết kế Checklist: **Cứ mỗi 30 phút, tạp vụ phải ký xác nhận sàn khô, gương sạch, đầy đủ nước súc miệng và bàn chải một lần.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('00b89aac-b0e7-49ec-ba48-fc4eccc7cb60','16-patient-experience','6947d6e9-69ef-4829-9205-021f31267be1',4,'Đồng bộ hạ tầng dữ liệu qua CRM','ong-bo-ha-tang-du-lieu-qua-crm',50,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f63da33-eb79-40f8-a24c-d157ceb5cd00','00b89aac-b0e7-49ec-ba48-fc4eccc7cb60',138,'text','Hệ thống trải nghiệm vận hành dựa trên thông tin, không dựa trên trí nhớ của con người. Khi Sales online ghi nhận khách hàng `Sợ_đau_mức_độ_cao`, dữ liệu này phải tự động hiển thị trên màn hình tiếp đón của Lễ tân, đồng thời đổ thẳng vào màn hình ghế nha của Bác sĩ trước khi ca khám bắt đầu. Sự mượt mà, không đứt gãy thông tin giữa các bộ phận chính là đỉnh cao của hệ thống vận hành CX.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fbcf2678-5055-4d14-854a-e425fd73a0eb','16-patient-experience','6947d6e9-69ef-4829-9205-021f31267be1',4,'Đo lường bằng các chỉ số kiểm soát (Data-Driven CX)','o-luong-bang-cac-chi-so-kiem-soat-data-driven-cx',51,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a63d0794-781d-42b6-84f8-a1f6c3510f36','fbcf2678-5055-4d14-854a-e425fd73a0eb',139,'text','Chúng ta quản trị trải nghiệm bằng các con số trên Dashboard, tuyệt đối không dùng cảm giác "hình như khách dạo này thích phòng khám mình lắm". Hệ thống phải trả về các chỉ số:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7eb56336-87aa-46e8-a02c-5ae9f4162211','fbcf2678-5055-4d14-854a-e425fd73a0eb',140,'text','- Tỷ lệ khách bùng hẹn (**No-show rate**).- Tỷ lệ khách đồng ý phác đồ sau khi khám (**Treatment Acceptance rate**).- Tỷ lệ lead chuyển hóa từ các bài review tự nhiên.- Số lượng đánh giá 5 sao tăng trưởng hàng tháng trên Google Maps.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('68097038-5612-41f3-83a1-400a492f02f6','16-patient-experience','6947d6e9-69ef-4829-9205-021f31267be1',4,'Kịch bản hóa và Tự động hóa (Automation)','kich-ban-hoa-va-tu-ong-hoa-automation',52,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('936a30c5-0f06-4d90-b058-48d49482e503','68097038-5612-41f3-83a1-400a492f02f6',141,'text','Hệ thống tự động phân loại bệnh nhân theo dịch vụ và mốc thời gian để tự động bắn các kịch bản chăm sóc (T+2h, T+24h, T+72h) thông qua Zalo OA. Con người không cần phải nhớ lịch, hệ thống sẽ tự nhắc nhở và thực thi theo một đường ống đã được thiết kế sẵn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5ee6acfd-3b52-4d89-8eae-58507d82f373','68097038-5612-41f3-83a1-400a492f02f6',142,'text','**Kết luận:** Thái độ phục vụ tốt chỉ là bề nổi của tảng băng chìm. Một hệ thống vận hành trải nghiệm bệnh nhân chặt chẽ phía dưới mới là thứ giúp phòng khám RHM của bạn tạo ra sự đồng bộ tối đa, giúp chất lượng dịch vụ tại cơ sở 1 hoàn toàn giống hệt cơ sở 2, cơ sở 3, tạo tiền đề vững chắc cho việc nhân chuỗi và tăng trưởng bùng nổ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5074262c-a026-4381-a0d4-c18f351984a2','16-patient-experience',NULL,2,'16.9 Kết luận - PATIENT EXPERIENCE là làm marketing bằng sự tử tế','169-ket-luan-patient-experience-la-lam-marketing-bang-su-tu-te',53,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fa94ba85-df3b-4f3b-a8d3-6098f5e60e41','5074262c-a026-4381-a0d4-c18f351984a2',143,'image',NULL,'book/16-patient-experience/017e6f59-fd36-4708-81ff-1691df41e91a-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('084d7fa2-0c1c-4a88-9b16-7db545fee14d','5074262c-a026-4381-a0d4-c18f351984a2',144,'text','Chúng ta đã cùng nhau đi qua trọn vẹn các lát cắt từ Khám, Điều trị, Chăm sóc hậu phẫu, Tái khám cho đến khâu Thu hoạch Review. Nếu phải dùng một cụm từ duy nhất để khái quát vai trò của **Patient Experience (Trải nghiệm bệnh nhân)** trong hệ điều hành Dental Empire OS, tôi sẽ gọi đó là: **Chiếc cầu nối vạn năng giữa chất lượng điều trị chuyên môn và bài toán tăng trưởng dài hạn của doanh nghiệp.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2cf6cc31-a5a4-4beb-a79b-c87c37c79c13','5074262c-a026-4381-a0d4-c18f351984a2',145,'text','Một phòng khám RHM sở hữu hệ thống trải nghiệm xuất sắc sẽ không bao giờ phải rơi vào cái bẫy "khát khách" hay phải kiệt quệ chạy đua đốt tiền cho quảng cáo. Bởi vì khi trải nghiệm đạt đến độ chín, nó sẽ tự động sinh ra những tầng giá trị thặng dư mà tiền bạc không thể mua đứt được:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f6d6f355-fed7-4a8c-82de-29893cd43b9e','5074262c-a026-4381-a0d4-c18f351984a2',146,'text','- **Hệ thống số hóa lòng biết ơn (Review Assets):** Những bài đánh giá 5 sao chân thực, sâu sắc liên tục được bơm lên Google Maps và mạng xã hội, đè bẹp mọi đối thủ trên không gian mạng.- **Tối ưu hóa chỉ số LTV (Tái khám đều đặn):** Bệnh nhân tự động quay lại bảo dưỡng răng định kỳ vì họ yêu mến và tin tưởng phòng khám, tạo ra dòng tiền đều đặn và bền vững.- **Hạ thấp chi phí Marketing (CAC):** Nhờ dòng chảy khách hàng giới thiệu (Referral) tăng trưởng không ngừng. Khách cũ tự động "bán hàng" hộ cho phòng khám bằng chính sự hài lòng của họ.- **Thiết lập pháo đài niềm tin:** Định vị thương hiệu nha khoa của bạn như một biểu tượng của sự uy tín, tử tế và đẳng cấp trong tâm trí thị trường đại chúng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3b405fc-83db-47b1-a092-5022804791a8','5074262c-a026-4381-a0d4-c18f351984a2',147,'text','**Mantra Dental Empire OS:** Tài sản lớn nhất của một phòng khám không phải là những chiếc máy triệu đô, mà là số lượng bệnh nhân sẵn sàng đứng ra bảo vệ và lan tỏa thương hiệu cho bạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('711751ef-9837-406d-824f-950cb10724c2','5074262c-a026-4381-a0d4-c18f351984a2',148,'text','Trong tư duy vận hành của chúng ta, Patient Experience chính là một bộ lọc chuyển hóa cảm xúc khách hàng tối thượng. Nó sở hữu năng lực kỳ diệu để biến một người lạ hoài nghi trở thành một người đồng hành trung thành, dịch chuyển liên tục qua 7 nấc thang giá trị:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0fc13e93-a520-4a33-a9cd-c55dd192eb6e','5074262c-a026-4381-a0d4-c18f351984a2',149,'text','Khi bạn vận hành phòng khám bằng một cái đầu lạnh của quy trình lâm sàng chuẩn xác (Clinic System) kết hợp với một trái tim nóng của hệ thống trải nghiệm thấu cảm (Patient Experience), bạn không chỉ đang chữa bệnh - bạn đang kiến tạo một đế chế nha khoa bền vững và thịnh vượng.',NULL,NULL,NULL,NULL,NULL);
